INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('107a7982-8e41-4850-b71c-72f10484b8c0', 'SLE', '2*x + y = 10, x - y = 2', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Let x be the first number and y be the second number. Based on the problem, ''The sum of twice a number and another number is 10'', what is the first equation?", "blank_expression": "Equation 1: ___", "correct_value": "2x + y = 10", "mapped_node_id": "SLE", "operation_description": "Formulating the first equation from the word problem"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Based on the problem, ''The first number minus the second number is 2'', what is the second equation?", "blank_expression": "Equation 2: ___", "correct_value": "x - y = 2", "mapped_node_id": "SLE", "operation_description": "Formulating the second equation from the word problem"}, {"step_index": 2, "step_type": "algebra", "instruction": "Add Equation 1 and Equation 2 to eliminate the variable ''y''. What is the resulting simplified equation?", "blank_expression": "(2x + y) + (x - y) = 10 + 2\n___", "correct_value": "3x = 12", "mapped_node_id": "SLE", "operation_description": "Adding equations (Elimination Method)"}, {"step_index": 3, "step_type": "algebra", "instruction": "Solve the equation for x.", "blank_expression": "x = ___", "correct_value": "4", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation in one variable"}, {"step_index": 4, "step_type": "algebra", "instruction": "Substitute the value of x (x = 4) into Equation 2 (x - y = 2). What is the simplified equation?", "blank_expression": "___ - y = 2", "correct_value": "4", "mapped_node_id": "SLE", "operation_description": "Substitution"}, {"step_index": 5, "step_type": "algebra", "instruction": "Solve the equation for y.", "blank_expression": "y = ___", "correct_value": "2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation in one variable"}, {"step_index": 6, "step_type": "algebra", "instruction": "State the solution as an ordered pair (x, y).", "blank_expression": "(x, y) = (___, ___)", "correct_value": "4, 2", "mapped_node_id": "SLE", "operation_description": "Stating the solution of the system"}]', '2026-05-19T16:20:30.011957+00:00', 'The sum of twice a number and another number is 10. The first number minus the second number is 2. What are the two numbers?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('2e4724b7-2ff5-41c0-a72f-b2f82a6e5ccc', 'SLE', 'x + y = 5, x - y = 1', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "In this problem, we need to find two numbers. Let x represent the first number. What does y represent?", "blank_expression": "Let y be the ___.", "correct_value": "second number", "mapped_node_id": "SLE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Based on the statement ''The sum of two numbers is 5'', write the first equation.", "blank_expression": "x + y = ___", "correct_value": "5", "mapped_node_id": "L2V", "operation_description": "Formulating equations"}, {"step_index": 2, "step_type": "variable_identification", "instruction": "Based on the statement ''Their difference is 1'', write the second equation.", "blank_expression": "x - y = ___", "correct_value": "1", "mapped_node_id": "L2V", "operation_description": "Formulating equations"}, {"step_index": 3, "step_type": "algebra", "instruction": "To eliminate y, add the two equations together. (x + y) + (x - y) = 5 + 1. Simplify the left side to 2x.", "blank_expression": "2x = ___", "correct_value": "6", "mapped_node_id": "SLE", "operation_description": "Adding equations (Elimination Method)"}, {"step_index": 4, "step_type": "algebra", "instruction": "Now, solve for x by dividing both sides by 2.", "blank_expression": "x = ___", "correct_value": "3", "mapped_node_id": "L1V", "operation_description": "Solving for a variable in a linear equation"}, {"step_index": 5, "step_type": "algebra", "instruction": "Substitute the value of x (which is 3) into the first equation (x + y = 5).", "blank_expression": "3 + y = ___", "correct_value": "5", "mapped_node_id": "AE", "operation_description": "Substitution"}, {"step_index": 6, "step_type": "algebra", "instruction": "Solve for y by subtracting 3 from both sides of the equation.", "blank_expression": "y = ___", "correct_value": "2", "mapped_node_id": "L1V", "operation_description": "Solving for a variable in a linear equation"}, {"step_index": 7, "step_type": "algebra", "instruction": "State the two numbers you found for x and y.", "blank_expression": "The first number is ___, and the second number is ___.", "correct_value": "3, 2", "mapped_node_id": "SLE", "operation_description": "Stating the solution"}]', '2026-05-19T16:20:43.693739+00:00', 'The sum of two numbers is 5. Their difference is 1. Find the two numbers.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b456cb49-d4a6-44a7-a288-9e57cec44e95', 'SLE', '3*x + 2*y = 12, x + y = 5', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify the starting expression to solve.", "blank_expression": "Expression = ___", "correct_value": "3*x + 2*y = 12, x + y = 5", "mapped_node_id": "SLE", "operation_description": "Variable identification"}]', '2026-05-19T16:20:44.135870+00:00', 'Solve the following algebra problem: 3*x + 2*y = 12, x + y = 5') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('902721b5-519a-47ae-9eb2-a52984b96c86', 'QE', 'x^2 + 5*x + 6 = 0', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify what the variable ''x'' represents in this problem.", "blank_expression": "Let x = ___", "correct_value": "the number", "mapped_node_id": "QE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Formulate the quadratic equation based on the problem description.", "blank_expression": "___ = 0", "correct_value": "x^2 + 5x + 6", "mapped_node_id": "QE", "operation_description": "Equation formulation"}, {"step_index": 2, "step_type": "algebra", "instruction": "Factor the quadratic expression on the left side of the equation.", "blank_expression": "(x + ___)(x + 3) = 0", "correct_value": "2", "mapped_node_id": "FP", "operation_description": "Factoring a trinomial"}, {"step_index": 3, "step_type": "algebra", "instruction": "Apply the Zero Product Property to set each factor equal to zero.", "blank_expression": "x + 2 = ___ or x + 3 = 0", "correct_value": "0", "mapped_node_id": "QE", "operation_description": "Applying Zero Product Property"}, {"step_index": 4, "step_type": "algebra", "instruction": "Solve the first linear equation for x.", "blank_expression": "x = ___", "correct_value": "-2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}, {"step_index": 5, "step_type": "algebra", "instruction": "Solve the second linear equation for x.", "blank_expression": "x = ___", "correct_value": "-3", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}, {"step_index": 6, "step_type": "algebra", "instruction": "State the possible values for the number.", "blank_expression": "The possible values for the number are ___ and -3.", "correct_value": "-2", "mapped_node_id": "QE", "operation_description": "Stating the solution set"}]', '2026-05-19T16:40:40.745207+00:00', 'The product of a number and a number increased by 5 is equal to negative 6. Find the possible values of this number.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ac91fab2-8f88-48ad-8cbc-20466cc96002', 'QE', 'x^2 - 4 = 0', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify what the variable ''x'' represents in the problem.", "blank_expression": "x represents the ___ of the garden in meters.", "correct_value": "side length", "mapped_node_id": "QE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Based on the problem, write the quadratic equation that represents the situation.", "blank_expression": "___ = 0", "correct_value": "x^2 - 4", "mapped_node_id": "QE", "operation_description": "Equation formulation"}, {"step_index": 2, "step_type": "algebra", "instruction": "Factor the quadratic expression using the difference of two squares.", "blank_expression": "(x - 2)(___) = 0", "correct_value": "x + 2", "mapped_node_id": "FP", "operation_description": "Factoring a difference of two squares"}, {"step_index": 3, "step_type": "algebra", "instruction": "Apply the Zero Product Property by setting each factor equal to zero.", "blank_expression": "x - 2 = 0 or ___ = 0", "correct_value": "x + 2", "mapped_node_id": "QE", "operation_description": "Applying Zero Product Property"}, {"step_index": 4, "step_type": "algebra", "instruction": "Solve the first linear equation for x.", "blank_expression": "x = ___", "correct_value": "2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}, {"step_index": 5, "step_type": "algebra", "instruction": "Solve the second linear equation for x.", "blank_expression": "x = ___", "correct_value": "-2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}]', '2026-05-19T16:40:51.499654+00:00', 'A square-shaped garden has an area. If 4 square meters are subtracted from the garden''s area, the result is 0. If ''x'' represents the side length of the garden in meters, what are the possible side lengths of the garden?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ed510627-cb98-43c8-bb7d-40fc93387d7f', 'QE', 'x^2 - 3*x + 2 = 0', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify what the variable x represents.", "blank_expression": "x = the ___ number", "correct_value": "unknown", "mapped_node_id": "QE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "The problem states that x^2 - 3x = -2. Rewrite this equation in the standard quadratic form (ax^2 + bx + c = 0).", "blank_expression": "___ = 0", "correct_value": "x^2 - 3x + 2", "mapped_node_id": "QE", "operation_description": "Formulating the equation"}, {"step_index": 2, "step_type": "algebra", "instruction": "Factor the quadratic expression x^2 - 3x + 2. Find two numbers that multiply to +2 and add to -3.", "blank_expression": "(x - ___)(x - ___) = 0", "correct_value": "1)(x - 2", "mapped_node_id": "FP", "operation_description": "Factoring the quadratic"}, {"step_index": 3, "step_type": "algebra", "instruction": "Apply the Zero Product Property: If the product of two factors is zero, then at least one of the factors must be zero. Set each factor equal to zero.", "blank_expression": "x - 1 = ___ OR x - 2 = ___", "correct_value": "0 OR x - 2 = 0", "mapped_node_id": "QE", "operation_description": "Applying Zero Product Property"}, {"step_index": 4, "step_type": "algebra", "instruction": "Solve the first linear equation for x.", "blank_expression": "x = ___", "correct_value": "1", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}, {"step_index": 5, "step_type": "algebra", "instruction": "Solve the second linear equation for x.", "blank_expression": "x = ___", "correct_value": "2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}]', '2026-05-19T16:41:08.754283+00:00', 'Sarah is thinking of a positive number. When she squares this number and then subtracts three times the original number, the result is -2. What positive number is Sarah thinking of?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('a23ed908-8970-4f0d-963f-b7a7aff4fdf9', 'QE', '2*x^2 + 4*x = 0', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify what the variable x represents in the problem.", "blank_expression": "Let x = ___", "correct_value": "the number", "mapped_node_id": "QE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Based on the problem, write the quadratic equation.", "blank_expression": "___ = 0", "correct_value": "2*x^2 + 4*x", "mapped_node_id": "QE", "operation_description": "Formulating the equation"}, {"step_index": 2, "step_type": "algebra", "instruction": "Factor out the Greatest Common Factor (GCF) from the left side of the equation.", "blank_expression": "2x(___ + 2) = 0", "correct_value": "x", "mapped_node_id": "FP", "operation_description": "Factoring out the GCF"}, {"step_index": 3, "step_type": "algebra", "instruction": "Apply the Zero Product Property by setting each factor equal to zero.", "blank_expression": "2x = ___ or x + 2 = ___", "correct_value": "0, 0", "mapped_node_id": "QE", "operation_description": "Applying the Zero Product Property"}, {"step_index": 4, "step_type": "algebra", "instruction": "Solve the first linear equation for x.", "blank_expression": "2x = 0\nx = ___", "correct_value": "0", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}, {"step_index": 5, "step_type": "algebra", "instruction": "Solve the second linear equation for x.", "blank_expression": "x + 2 = 0\nx = ___", "correct_value": "-2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}]', '2026-05-19T16:41:18.140377+00:00', 'The square of a number, multiplied by 2, is equal to negative four times the number. What are the possible values for this number?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('578ddd18-1bfc-48a3-9b17-dbc61943dbaf', 'QE', 'x^2 - x - 6 = 0', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify what the variable ''x'' represents in this problem.", "blank_expression": "Let x = ___", "correct_value": "the larger number", "mapped_node_id": "QE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Based on the problem description, form the quadratic equation.", "blank_expression": "The equation representing the problem is: ___", "correct_value": "x^2 - x - 6 = 0", "mapped_node_id": "QE", "operation_description": "Formulating the quadratic equation"}, {"step_index": 2, "step_type": "algebra", "instruction": "Factor the quadratic expression completely.", "blank_expression": "(x - ___)(x + ___) = 0", "correct_value": "3)(x + 2", "mapped_node_id": "FP", "operation_description": "Factoring a quadratic trinomial"}, {"step_index": 3, "step_type": "algebra", "instruction": "Using the Zero-Product Property, set each factor equal to zero.", "blank_expression": "x - ___ = 0 or x + ___ = 0", "correct_value": "3 or x + 2", "mapped_node_id": "QE", "operation_description": "Applying the Zero-Product Property"}, {"step_index": 4, "step_type": "algebra", "instruction": "Solve each resulting linear equation for x.", "blank_expression": "x = ___ or x = ___", "correct_value": "3 or x = -2", "mapped_node_id": "QE", "operation_description": "Solving linear equations and identifying solutions"}]', '2026-05-19T16:41:37.023064+00:00', 'The product of two numbers is 6. One of the numbers is 1 less than the other number. If ''x'' represents the larger number, what are the possible values for ''x''?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('6bcbb57d-b79d-4a53-bf16-5f3150f88377', 'QE', 'x^2 + 5*x + 6 = 0', '[{"step_index": 0, "step_type": "variable_identification", "instruction": "Identify what the variable x represents in this problem.", "blank_expression": "Let x be ___", "correct_value": "the number", "mapped_node_id": "QE", "operation_description": "Variable identification"}, {"step_index": 1, "step_type": "variable_identification", "instruction": "Based on the problem description, write down the quadratic equation.", "blank_expression": "___ = 0", "correct_value": "x^2 + 5x + 6", "mapped_node_id": "QE", "operation_description": "Setting up the equation"}, {"step_index": 2, "step_type": "algebra", "instruction": "Factor the quadratic expression on the left side of the equation.", "blank_expression": "(x + ___)(x + ___) = 0", "correct_value": "2, 3", "mapped_node_id": "FP", "operation_description": "Factoring a trinomial"}, {"step_index": 3, "step_type": "algebra", "instruction": "Apply the Zero Product Property by setting each factor equal to zero.", "blank_expression": "x + ___ = 0 or x + ___ = 0", "correct_value": "2, 3", "mapped_node_id": "QE", "operation_description": "Applying the Zero Product Property"}, {"step_index": 4, "step_type": "algebra", "instruction": "Solve the first linear equation for x.", "blank_expression": "x = ___", "correct_value": "-2", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}, {"step_index": 5, "step_type": "algebra", "instruction": "Solve the second linear equation for x.", "blank_expression": "x = ___", "correct_value": "-3", "mapped_node_id": "L1V", "operation_description": "Solving a linear equation"}]', '2026-05-19T16:41:50.998654+00:00', 'The product of two algebraic expressions results in zero. The first expression is ''a number increased by 2'', and the second expression is ''the same number increased by 3''. Determine the possible values of this number.') ON CONFLICT DO NOTHING;
