INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('3721ebcc-8be4-4d4b-92ee-3b06ffbc4fd9', 'FD', '1/2 + 1/4', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang dami ng asukal sa pamamagitan ng pag-aadd ng dalawang sukat.", "blank_expression": "1/2 + 1/4 = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Gawing magkatulad ang denominator ng mga fraction.", "blank_expression": "2/4 + 1/4 = ___", "correct_value": "3/4", "operation_description": "Add the fractions", "mapped_node_id": "FD"}]', '2026-05-21T12:22:56.247072+00:00', 'Si Aling Nena ay bumili ng kalahating kilo ng asukal para sa kanyang sari-sari store at dinagdagan niya ito ng isang kapat na kilo pa. Ilang kilo ng asukal ang kabuuang nabili ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e4138420-1ab8-40cc-ae58-2b00495940d2', 'FD', '3/4 - 1/8', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang dami ng asukal na natira.", "blank_expression": "x = 3/4 - 1/8", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Gawing pareho ang denominator ng mga fraction.", "blank_expression": "3/4 - 1/8 = __/8 - 1/8", "correct_value": "6", "operation_description": "Find common denominator", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-subtract ang mga numerator.", "blank_expression": "6/8 - 1/8 = __/8", "correct_value": "5", "operation_description": "Subtract fractions", "mapped_node_id": "FD"}]', '2026-05-21T12:23:04.843551+00:00', 'Si Aling Nena ay may 3/4 na kilo ng asukal sa kanyang sari-sari store. Ginamit niya ang 1/8 na kilo para sa paggawa ng kanyang pambentang meryenda.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ea1c25c7-9e27-499a-8f40-4be6829a2c28', 'FD', '2/3 * 3/4', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang bahagi ng asukal na gagamitin.", "blank_expression": "___ = 2/3 * 3/4", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "I-multiply ang mga numerator at denominator.", "blank_expression": "x = ___ / (3 * 4)", "correct_value": "2 * 3", "operation_description": "Multiply the fractions", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-cancel ang common factor na 3.", "blank_expression": "x = ___", "correct_value": "2/4", "operation_description": "Cancel common terms", "mapped_node_id": "FD"}, {"step_index": 3, "type": "algebra", "instruction": "I-simplify ang fraction sa pinakamababang term.", "blank_expression": "x = ___", "correct_value": "1/2", "operation_description": "Simplify fraction", "mapped_node_id": "FD"}]', '2026-05-21T12:23:13.997837+00:00', 'Si Aling Nena ay may 2/3 ng isang kilong asukal sa kanyang sari-sari store. Kung gagamitin niya ang 3/4 ng natitirang asukal para sa paggawa ng kakanin, gaano karaming kilo ng asukal ang kanyang magagamit?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('497947c8-7086-46f0-9396-d03ec10d910a', 'FD', '5/6 - 1/3', '[{"step_index": 0, "type": "variable_id", "instruction": "Ilista ang kabuuang asukal at ang asukal na ginamit.", "blank_expression": "___ - ___ = x", "correct_value": "5/6 - 1/3", "operation_description": "Write the equation", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Hanapin ang common denominator para sa 6 at 3.", "blank_expression": "5/6 - ___ = x", "correct_value": "2/6", "operation_description": "Find common denominator", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-subtract ang mga numerator at i-simplify ang sagot.", "blank_expression": "3/6 = ___", "correct_value": "1/2", "operation_description": "Subtract and simplify", "mapped_node_id": "FD"}]', '2026-05-21T12:23:22.972088+00:00', 'Si Aling Nena ay mayroong 5/6 na kilo ng asukal sa kanyang sari-sari store. Ginamit niya ang 1/3 na kilo nito para sa paggawa ng biko, ilang kilo ng asukal ang natira sa kanya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b596049a-fea9-4a66-bf32-0510b985839a', 'FD', '1/4 + 3/8', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang dami ng asukal.", "blank_expression": "x = 1/4 + 3/8", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Ipareho ang denominator ng mga fraction.", "blank_expression": "2/8 + 3/8 = ___", "correct_value": "5/8", "operation_description": "Add fractions", "mapped_node_id": "FD"}]', '2026-05-21T12:23:32.036113+00:00', 'Si Aling Nena ay bumili ng 1/4 kilo ng asukal para sa kanyang kakanin at dagdag na 3/8 kilo pa para sa kanyang inumin. Ilang kilo ng asukal ang kabuuang binili ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('cf851bfa-2985-4c73-abc7-8ab9df66cc63', 'FD', '7/8 - 1/2', '[{"step_index": 0, "type": "variable_id", "instruction": "Ilista ang mga fraction na ibinigay sa problema.", "blank_expression": "___ - ___ = x", "correct_value": "7/8, 1/2", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Gawing magkapareho ang denominator ng mga fraction.", "blank_expression": "7/8 - __ = x", "correct_value": "4/8", "operation_description": "Find common denominator", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-subtract ang mga numerator.", "blank_expression": "(7 - 4) / 8 = __", "correct_value": "3/8", "operation_description": "Subtract fractions", "mapped_node_id": "FD"}]', '2026-05-21T12:23:41.003324+00:00', 'Si Aling Nena ay mayroong \frac{7}{8} kilo ng asukal sa kanyang sari-sari store. Ginamit niya ang \frac{1}{2} kilo para sa paggawa ng palamig, ilan pang kilo ng asukal ang natitira sa kanya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('30bfdf94-ec58-40d3-a5e7-408354735917', 'FD', '3/5 + 1/10', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang timbang ng asukal sa pamamagitan ng pag-add ng dalawang fraction.", "blank_expression": "x = 3/5 + 1/10", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Gawing 10 ang denominator ng 3/5.", "blank_expression": "___/10 + 1/10", "correct_value": "6", "operation_description": "Find common denominator", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-add ang mga numerator.", "blank_expression": "(6 + 1)/10 = ___/10", "correct_value": "7", "operation_description": "Add fractions", "mapped_node_id": "FD"}]', '2026-05-21T12:23:49.837669+00:00', 'Si Aling Nena ay bumili ng 3/5 na kilo ng asukal para sa kanyang kakanin at 1/10 na kilo pa para sa kanyang kape. Ilang kilo ng asukal ang kabuuang binili ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('8d6affbb-7ca6-47fa-a0fb-d25f864d8493', 'FD', '2/3 - 1/6', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang asukal at ang asukal na ginamit.", "blank_expression": "Total = 2/3, Used = ___", "correct_value": "1/6", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Hanapin ang common denominator para sa 2/3 at 1/6.", "blank_expression": "4/6 - 1/6 = ___", "correct_value": "3/6", "operation_description": "Subtract fractions", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang fraction.", "blank_expression": "3/6 = ___", "correct_value": "1/2", "operation_description": "Simplify fraction", "mapped_node_id": "FD"}]', '2026-05-21T12:24:01.166082+00:00', 'Si Aling Nena ay may 2/3 ng isang kilong asukal sa kanyang sari-sari store. Ginamit niya ang 1/6 ng kilo para sa paggawa ng kanyang palamig, ilan ang natirang asukal?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ce03d640-2a74-4bda-8138-023efba618d0', 'FD', '3/4 * 2/3', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang equation para malaman kung gaano karaming asukal ang nagamit.", "blank_expression": "___ = 3/4 * 2/3", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "I-multiply ang mga numerator at denominator.", "blank_expression": "x = ___ / (4 * 3)", "correct_value": "3 * 2", "operation_description": "MULTIPLY_FRACTIONS", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang fraction sa pamamagitan ng pag-cancel ng common terms.", "blank_expression": "x = ___", "correct_value": "2 / 4", "operation_description": "CANCEL_TERMS", "mapped_node_id": "FD"}, {"step_index": 3, "type": "algebra", "instruction": "I-simplify ang fraction sa pinakamababang term nito.", "blank_expression": "x = ___", "correct_value": "1 / 2", "operation_description": "SIMPLIFY_FRACTION", "mapped_node_id": "FD"}]', '2026-05-21T12:24:12.017423+00:00', 'Si Aling Nena ay may 3/4 na kilo ng asukal sa kanyang sari-sari store. Ginamit niya ang 2/3 nito para sa paggawa ng palamig na ibebenta niya.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('6e6fb918-6016-445f-9f9e-2c47f7d805c1', 'FD', '5/8 + 1/4', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang timbang ng asukal sa pamamagitan ng pag-aadd ng mga fractions.", "blank_expression": "5/8 + 1/4 = ___", "correct_value": "5/8 + 1/4", "operation_description": "Write the equation", "mapped_node_id": "FD"}, {"step_index": 1, "type": "algebra", "instruction": "Hanapin ang common denominator upang mai-add ang mga fraction.", "blank_expression": "5/8 + 2/8 = ___", "correct_value": "7/8", "operation_description": "ADD_FRACTIONS", "mapped_node_id": "FD"}]', '2026-05-21T12:24:23.867283+00:00', 'Si Aling Nena ay bumili ng 5/8 kilo ng asukal para sa kanyang kakanin at dagdag na 1/4 kilo pa para sa kanyang tinda sa sari-sari store. Ilang kilo ng asukal ang kabuuang binili ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('090183bb-95a7-40c0-8bea-3994d2461b2a', 'OI', '-3 + 7', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang integer na kumakatawan sa utang at sa ibinayad na pera.", "blank_expression": "___ + ___", "correct_value": "-3 + 7", "operation_description": "Write the equation", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga integers upang makuha ang huling halaga.", "blank_expression": "-3 + 7 = ___", "correct_value": "4", "operation_description": "SIMPLIFY_ARITHMETIC", "mapped_node_id": "OI"}]', '2026-05-21T12:24:34.661340+00:00', 'Si Aling Nena ay may utang na 3 piso sa kanyang suking tindahan. Nang siya ay nagbayad ng 7 piso, magkano na ang magiging balanse niya o sobra sa kanyang bayad?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b08fb969-f5d3-4b84-806d-5bf06d6b4c74', 'OI', '-5 - (-2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang integer na kumakatawan sa utang ni Aling Nena.", "blank_expression": "Utang = ___", "correct_value": "-5", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "variable_id", "instruction": "Tukuyin ang integer na kumakatawan sa pagbabayad ng utang.", "blank_expression": "Pagbabayad = ___", "correct_value": "-2", "operation_description": "Write the equation", "mapped_node_id": "OI"}, {"step_index": 2, "type": "algebra", "instruction": "Baguhin ang operasyon ng pagbabawas sa pagdaragdag ng kabaligtaran (additive inverse).", "blank_expression": "-5 + ___", "correct_value": "2", "operation_description": "RESOLVE_DOUBLE_MINUS", "mapped_node_id": "OI"}, {"step_index": 3, "type": "algebra", "instruction": "Pagsamahin ang mga numero upang makuha ang huling sagot.", "blank_expression": "-5 + 2 = ___", "correct_value": "-3", "operation_description": "SIMPLIFY_ARITHMETIC", "mapped_node_id": "OI"}]', '2026-05-21T12:24:45.108446+00:00', 'Si Aling Nena ay may utang na 5 piso sa kanyang suki sa palengke. Nang magbayad siya ng utang na 2 piso, magkano na lamang ang kanyang natitirang utang?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('6a749b86-a4d8-4ae5-a53c-f0469d49169b', 'OI', '4 * -3', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang bilang ng transaksyon at ang halagang nababawas sa bawat isa.", "blank_expression": "___ * ___ = x", "correct_value": "4 * -3", "operation_description": "Write the equation", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "I-multiply ang mga numero gamit ang rules for integers.", "blank_expression": "4 * -3 = ___", "correct_value": "-12", "operation_description": "SIMPLIFY_ARITHMETIC", "mapped_node_id": "OI"}]', '2026-05-21T12:24:54.819837+00:00', 'Si Aling Nena ay nagbawas ng 3 piso mula sa kanyang kita sa loob ng 4 na magkakasunod na transaksyon dahil sa pagbabayad ng utang. Magkano ang kabuuang bawas sa kanyang kita?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('18db8a1d-7f23-47ea-82ca-b15d996d4ca0', 'OI', '-12 / 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Ilista ang kabuuang utang bilang isang negative integer at ang bilang ng araw bilang divisor.", "blank_expression": "Utang = ___, Araw = 4", "correct_value": "-12", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang mathematical expression para sa utang bawat araw.", "blank_expression": "___ / 4", "correct_value": "-12", "operation_description": "Write the equation", "mapped_node_id": "OI"}, {"step_index": 2, "type": "algebra", "instruction": "I-divide ang negative na numero sa positive na numero.", "blank_expression": "-12 / 4 = ___", "correct_value": "-3", "operation_description": "Divide integers", "mapped_node_id": "OI"}]', '2026-05-21T12:25:04.298338+00:00', 'Si Aling Nena ay may utang na Php 12 sa kanyang suking sari-sari store dahil sa pagbili ng load. Kung hahatiin niya ang pagbabayad nito sa loob ng 4 na araw, magkano ang kailangan niyang ibawas sa kanyang baon bawat araw?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('4a8bd59d-d4cb-4901-8517-9f51347ce364', 'OI', '6 + (-9)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang panimulang halaga ng pera at ang halagang ibinayad.", "blank_expression": "6 + (___) = x", "correct_value": "-9", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga integers upang makuha ang huling balanse.", "blank_expression": "6 + (-9) = ___", "correct_value": "-3", "operation_description": "SIMPLIFY_ARITHMETIC", "mapped_node_id": "OI"}]', '2026-05-21T12:25:13.263928+00:00', 'Si Aling Nena ay may 6 na pisong barya sa kanyang kaha. Binayaran niya ang delivery rider ng 9 na piso para sa kanyang biniling load, kaya nabawasan ang kanyang pera.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('354a0ffb-9e62-4cd9-ad6c-76d20efa1e9a', 'OI', '-8 + 3', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang numerong kumakatawan sa utang ni Aling Nena.", "blank_expression": "Utang = ___", "correct_value": "-8", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang kabuuang equation para makuha ang natitirang utang.", "blank_expression": "___ + 3 = x", "correct_value": "-8", "operation_description": "Write the equation", "mapped_node_id": "OI"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang operasyon ng integers.", "blank_expression": "-8 + 3 = ___", "correct_value": "-5", "operation_description": "Simplify arithmetic", "mapped_node_id": "OI"}]', '2026-05-21T12:25:23.008528+00:00', 'Si Aling Nena ay may utang na 8 pesos sa tindahan para sa kanyang biniling sardinas. Nagbayad siya ng 3 pesos sa tindera, kaya magkano pa ang natitirang utang ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('24fdb3a9-a998-41a3-963f-d55ee5cac169', 'OI', '(-4) * (-5)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the number of creditors and the amount of debt per person as integers.", "blank_expression": "Number of creditors: ___, Debt per person: ___", "correct_value": "5, -4", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "Multiply the integers to find the total debt.", "blank_expression": "(-4) * (-5) = __", "correct_value": "20", "operation_description": "Multiply negative integers", "mapped_node_id": "OI"}]', '2026-05-21T12:25:43.386705+00:00', 'Si Aling Nena ay may utang na 4 na piso sa bawat isa sa kanyang 5 suki para sa binili niyang mga sangkap sa sari-sari store. Kung babayaran niya ang lahat ng kanyang utang, magkano ang kabuuang halaga na mababawas sa kanyang pera?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d601494e-1923-4c3f-a7a9-c96cc175cce8', 'OI', '10 / (-2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang halaga ng utang (gamitin ang negative sign dahil ito ay utang) at ang bilang ng hulog.", "blank_expression": "Utang = ___, Bilang ng hulog = 2", "correct_value": "-10", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "I-divide ang -10 sa 2.", "blank_expression": "-10 / 2 = ___", "correct_value": "-5", "operation_description": "Simplify the division", "mapped_node_id": "OI"}]', '2026-05-21T12:25:51.962758+00:00', 'Si Aling Nena ay may utang na 10 pesos sa kanyang suki na tindahan. Kung babayaran niya ito sa loob ng 2 pantay na hulog, magkano ang mababawas sa kanyang utang bawat hulog?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('17bc4031-6e8a-4d5e-b05e-4f599669f543', 'OI', '-7 - 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kinakatawan ng mga numero sa problema kung ang utang ay itinuturing na negative integer.", "blank_expression": "Utang 1: ___, Utang 2: ___", "correct_value": "-7, -4", "operation_description": "Write the equation", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "Isulat ang operasyon para sa pagsasama ng dalawang utang.", "blank_expression": "-7 - 4 = -7 + ___", "correct_value": "-4", "operation_description": "Convert subtraction to addition", "mapped_node_id": "OI"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang dalawang negative na numero.", "blank_expression": "-7 + -4 = ___", "correct_value": "-11", "operation_description": "Simplify arithmetic", "mapped_node_id": "OI"}]', '2026-05-21T12:26:04.550605+00:00', 'Si Aling Nena ay may utang na 7 pesos sa tindahan para sa kanyang biniling kendi. Nangutang siya ulit ng 4 na pesos para sa pambayad sa kuryente, kaya lalong lumaki ang kanyang kabuuang utang.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('4cb854f6-1ba2-4641-9d02-e421bd8cdcb9', 'OI', '(-3) + (-6)', '[{"step_index": 0, "type": "variable_id", "instruction": "Irepresenta ang unang utang at ang karagdagang utang bilang mga integer.", "blank_expression": "(___) + (___) = x", "correct_value": "-3, -6", "operation_description": "Identify the variable", "mapped_node_id": "OI"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang dalawang negatibong bilang.", "blank_expression": "-3 + -6 = ___", "correct_value": "-9", "operation_description": "Simplify arithmetic", "mapped_node_id": "OI"}]', '2026-05-21T12:26:14.149867+00:00', 'Si Aling Nena ay may utang na 3 piso sa kanyang suki dahil sa kulang na pambayad sa itlog, at nangutang pa siya ng 6 na piso para sa sardinas. Magkano ang kabuuang utang ni Aling Nena sa tindahan?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('2ea6a79d-a72d-48a3-aa5a-80467d8a9d9c', 'LE', 'x^2 * x^3', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na ginagamit sa problema.", "blank_expression": "variable = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Product Rule of Exponents kung saan pinagsasama ang mga exponents.", "blank_expression": "x^2 * x^3 = x^(2 + 3) = x^___", "correct_value": "5", "operation_description": "Apply Product Rule", "mapped_node_id": "LE"}]', '2026-05-21T12:26:31.523978+00:00', 'Si Aling Nena ay may sari-sari store at nagbebenta ng mga eco-bag. Kung mayroon siyang x^2 na piraso ng eco-bag sa isang pack at bumili siya ng x^3 na pack, gaano karaming eco-bag ang kabuuan na mayroon siya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('701cba37-17f7-4102-bb3a-4968533b9d61', 'LE', 'x^5 / x^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang base ng expression na ginagamit sa problema.", "blank_expression": "base = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Quotient Rule sa pamamagitan ng pag-subtract ng exponent sa denominator mula sa exponent sa numerator.", "blank_expression": "x^5 / x^2 = x^(___)", "correct_value": "5-2", "operation_description": "Subtract exponents", "mapped_node_id": "LE"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang resulta ng subtraction upang makuha ang final answer.", "blank_expression": "x^(5-2) = x^___", "correct_value": "3", "operation_description": "Simplify arithmetic", "mapped_node_id": "LE"}]', '2026-05-21T12:26:42.362447+00:00', 'Si Aling Nena ay may $x^5$ na piraso ng kendi sa isang malaking garapon para sa kanyang sari-sari store. Kung ipinamahagi niya ang mga ito nang pantay-pantay sa $x^2$ na bilang ng mga batang suki, ilang kendi ang matatanggap ng bawat bata?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('69d134a4-093c-45cd-8b32-867a694aea8b', 'LE', '(x^2)^3', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang base at ang mga exponent sa ibinigay na ekspresyon.", "blank_expression": "(x^2)^3 = x^{\\underline{\\quad}}", "correct_value": "2*3", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Power of a Power Rule sa pamamagitan ng pagmu-multiply ng mga exponent.", "blank_expression": "(x^2)^3 = x^{\\underline{\\quad}}", "correct_value": "6", "operation_description": "Multiply the exponents", "mapped_node_id": "LE"}]', '2026-05-21T12:27:01.063171+00:00', 'Si Aling Nena ay may tinitindang mga supot ng kendi sa kanyang sari-sari store. Kung mayroong x^2 na piraso ng kendi sa bawat supot at mayroon siyang (x^2)^3 na kabuuang dami ng kendi sa loob ng isang malaking lalagyan, paano ito isusulat sa simpleng anyo? Gamitin ang batas ng exponent upang makuha ang katumbas na ekspresyon.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('530fc30d-1628-49e4-984b-9bed7dc96ed3', 'LE', 'x^3 * x^(-1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang base na ginagamit sa problema.", "blank_expression": "base = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Product Rule of Exponents sa pag-add ng exponents.", "blank_expression": "x^{3 + (-1)} = x^{___}", "correct_value": "2", "operation_description": "Apply Product Rule", "mapped_node_id": "LE"}]', '2026-05-21T12:27:09.800828+00:00', 'Si Aling Nena ay may $x^3$ na supot ng kendi sa kanyang sari-sari store. Nakapagbenta siya ng $x^{-1}$ na bahagi ng kanyang stock para sa mga bata sa eskwelahan.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b71c1931-bb92-42e2-aff5-eace763223dd', 'LE', '(x^3)^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang base ng expression base sa word problem.", "blank_expression": "base = ___", "correct_value": "x^3", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Power of a Power Rule sa pamamagitan ng pag-multiply ng mga exponent.", "blank_expression": "(x^3)^2 = x^(___)", "correct_value": "3*2", "operation_description": "Multiply exponents", "mapped_node_id": "LE"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang huling sagot sa pamamagitan ng pag-simplify ng exponent.", "blank_expression": "x^6 = x^___", "correct_value": "6", "operation_description": "Simplify", "mapped_node_id": "LE"}]', '2026-05-21T12:27:19.298755+00:00', 'Si Aling Nena ay may 3 na basket ng mga kendi, at ang bawat basket ay may 3 patong ng mga pakete. Kung ang bawat patong ay may x na bilang ng kendi sa loob ng isang partikular na lalagyan, ilang kendi ang mayroon sa loob ng 2 grupo ng mga basket na ito?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('00c48509-5849-4e99-9625-baf783da8098', 'LE', 'x^4 / x^4', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression para sa bilang ng kendi bawat bata.", "blank_expression": "___", "correct_value": "x^4 / x^4", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Quotient Rule o kanselahin ang mga parehong term.", "blank_expression": "x^4 / x^4 = ___", "correct_value": "1", "operation_description": "Simplify the expression", "mapped_node_id": "LE"}]', '2026-05-21T12:27:28.571990+00:00', 'Si Aling Nena ay mayroong x^4 na piraso ng kendi sa isang garapon at ibinahagi niya ito nang pantay sa x^4 na bilang ng mga bata. Ilang kendi ang natanggap ng bawat bata?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('17250e14-1dd5-4d56-9350-a36a1c2ad56a', 'LE', 'x^2 * x^2 * x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na ginamit sa ating expression.", "blank_expression": "variable = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Product Rule para sa exponents sa pamamagitan ng pag-add ng exponents ng parehong base.", "blank_expression": "x^2 * x^2 * x^1 = x^{___}", "correct_value": "5", "operation_description": "Apply Product Rule of Exponents", "mapped_node_id": "LE"}]', '2026-05-21T12:27:39.970861+00:00', 'Si Aling Nena ay nag-aayos ng kanyang sari-sari store at nakapila ang kanyang mga paninda. Mayroon siyang x^2 na hanay ng mga sitsirya, kung saan ang bawat hanay ay may x^2 na piraso, at may dagdag pa siyang x na piraso sa isang tabi. Ilan lahat ang kabuuang bilang ng sitsirya na mayroon si Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('314ae144-27bf-40eb-b387-58b077eeb191', 'LE', '(x^2 * x^3) / x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression para sa kabuuang bilang ng kendi na hinati sa dami ng bata.", "blank_expression": "___", "correct_value": "(x^2 * x^3) / x", "operation_description": "Write the equation", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Product Law of Exponents sa numerator.", "blank_expression": "x^(___) / x", "correct_value": "5", "operation_description": "Product Law", "mapped_node_id": "LE"}, {"step_index": 2, "type": "algebra", "instruction": "Gamitin ang Quotient Law of Exponents para makuha ang final answer.", "blank_expression": "x^(___)", "correct_value": "4", "operation_description": "Quotient Law", "mapped_node_id": "LE"}]', '2026-05-21T12:27:48.653181+00:00', 'Si Aling Nena ay may $x^2$ na bilang ng supot ng kendi sa isang lalagyan at bumili pa siya ng $x^3$ na karagdagang supot. Kung ipapamahagi niya ang lahat ng kendi sa $x$ na bilang ng mga bata, ilang supot ng kendi ang matatanggap ng bawat isa?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e4e15015-1d1b-496e-9101-ecbc2d713c63', 'LE', 'x^6 / x^3', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the total number of candies and the number of bags.", "blank_expression": "Total candies = ___, Number of bags = ___", "correct_value": "x^6, x^3", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Apply the Quotient Rule for exponents by subtracting the denominator''s exponent from the numerator''s.", "blank_expression": "x^6 / x^3 = x^(6 - 3) = x^___", "correct_value": "3", "operation_description": "Subtract exponents", "mapped_node_id": "LE"}]', '2026-05-21T12:27:58.279399+00:00', 'A sari-sari store owner has a bulk pack of candies containing x^6 pieces that she wants to distribute equally into x^3 small plastic bags. How many candies will each plastic bag contain?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('a117dfa8-b5af-4740-a6cc-10afe28c7dde', 'LE', '(x^4)^0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang expression na kailangang i-simplify.", "blank_expression": "Expression = ___", "correct_value": "(x^4)^0", "operation_description": "Identify the variable", "mapped_node_id": "LE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Zero Exponent Rule upang i-simplify ang expression.", "blank_expression": "(x^4)^0 = ___", "correct_value": "1", "operation_description": "Apply zero exponent rule", "mapped_node_id": "LE"}]', '2026-05-21T12:28:06.582267+00:00', 'Si Aling Nena ay may (x^4) na piraso ng kendi sa loob ng isang garapon na hindi pa niya nabubuksan kaya ito ay itinakda sa power of 0. Ilang piraso ng kendi ang talagang mayroon siya para ibenta?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e3da7529-9f0c-474e-b319-3cf40440ebf2', 'SP', '(x+2)*(x+3)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang expression para sa area ng garden gamit ang formula na Area = length * width.", "blank_expression": "Area = (x + 2) * (___)", "correct_value": "x + 3", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang mga terms gamit ang FOIL method.", "blank_expression": "Area = x^2 + 3x + 2x + ___", "correct_value": "6", "operation_description": "DISTRIBUTE", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na terms (like terms).", "blank_expression": "Area = x^2 + ___ + 6", "correct_value": "5x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "SP"}]', '2026-05-21T12:28:15.373251+00:00', 'Si Aling Nena ay nagpaplano ng hugis-parihaba na garden sa tabi ng kanyang sari-sari store. Ang haba nito ay (x + 3) metro at ang lapad naman ay (x + 2) metro. Ano ang kabuuang area ng garden ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('28554e62-902b-4239-af54-0dde0c83520f', 'SP', '(x+1)*(x-1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang expression para sa area ng rectangle (Length multiplied by Width).", "blank_expression": "Area = (x + 1) * (x - 1)", "correct_value": "(x + 1) * (x - 1)", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang mga terms gamit ang FOIL method.", "blank_expression": "___ - x + x - 1", "correct_value": "x^2", "operation_description": "DISTRIBUTE", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga like terms (-x at +x).", "blank_expression": "x^2 + ___ - 1", "correct_value": "0", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "SP"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang final simplified expression.", "blank_expression": "x^2 ___", "correct_value": "- 1", "operation_description": "REMOVE_ADDING_ZERO", "mapped_node_id": "SP"}]', '2026-05-21T12:28:24.832974+00:00', 'Si Aling Nena ay may square na garden na may side length na x metro. Nagbawas siya ng 1 metro sa isang side at nagdagdag naman ng 1 metro sa kabilang side para maging rectangular ang garden, ano ang magiging area nito?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('f39b465f-7c6e-46a8-b0c5-3654f40c632f', 'SP', '(x+3)^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang formula para sa area ng square (Side squared).", "blank_expression": "Area = (___)^2", "correct_value": "x+3", "operation_description": "Identify the variable", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang square of a binomial formula: (a+b)^2 = a^2 + 2ab + b^2. Kunin ang square ng unang term.", "blank_expression": "x^2 + 2(x)(3) + 3^2 = ___ + 6x + 9", "correct_value": "x^2", "operation_description": "Square the first term", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square ng huling term.", "blank_expression": "x^2 + 6x + ___", "correct_value": "9", "operation_description": "Square the last term", "mapped_node_id": "SP"}]', '2026-05-21T12:28:33.412946+00:00', 'Si Aling Nena ay may square-shaped na plot ng lupa sa harap ng kanyang sari-sari store na may sukat na (x + 3) meters ang bawat gilid. Ano ang kabuuang area ng lupa na kailangang lagyan ng mga paso ng halaman?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('fa32a97c-23c6-4ad9-b9a9-4ffacc7308df', 'SP', '(2x+1)*(x+4)', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang expression para sa area ng eco-bag gamit ang formula na Area = length * width.", "blank_expression": "Area = (2x + 1) * (___)", "correct_value": "x + 4", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang FOIL method para i-multiply ang mga terms.", "blank_expression": "Area = ___ + 8x + x + 4", "correct_value": "2x^2", "operation_description": "DISTRIBUTE", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na terms (like terms).", "blank_expression": "Area = 2x^2 + ___ + 4", "correct_value": "9x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "SP"}]', '2026-05-21T12:28:42.469195+00:00', 'Si Aling Nena ay nagbebenta ng mga eco-bag sa kanyang sari-sari store. Ang haba ng bawat eco-bag ay (x + 4) na sentimetro at ang lapad nito ay (2x + 1) na sentimetro.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('5a21fb9f-62c1-43eb-8e46-d6215f279be9', 'SP', '(x-2)^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang formula para sa area ng square (Side x Side).", "blank_expression": "Area = (___)^2", "correct_value": "x-2", "operation_description": "Identify the variable", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang pattern na (a-b)^2 = a^2 - 2ab + b^2 upang i-expand ang expression.", "blank_expression": "(x-2)^2 = x^2 - __ + 4", "correct_value": "4x", "operation_description": "Apply square of a binomial pattern", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang huling simplified na sagot.", "blank_expression": "(x-2)^2 = __", "correct_value": "x^2-4x+4", "operation_description": "Final simplified form", "mapped_node_id": "SP"}]', '2026-05-21T12:28:50.938883+00:00', 'Si Aling Nena ay nagdisenyo ng isang parisukat na garden plot sa kanyang bakuran na may side length na (x-2) meters. Ilang square meters ang magiging area ng kanyang garden plot?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('73cab5a5-592a-49a5-83c0-9046b614d9b4', 'SP', '(x+4)*(x-4)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the expression for the length and width of the garden based on the change.", "blank_expression": "Area = (x + 4)(x - 4)", "correct_value": "(x + 4)(x - 4)", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "Distribute the terms using the FOIL method.", "blank_expression": "___ - 4x + 4x - 16", "correct_value": "x^2", "operation_description": "Distribute", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Combine the middle terms.", "blank_expression": "x^2 + ___ - 16", "correct_value": "0", "operation_description": "Collect and combine like terms", "mapped_node_id": "SP"}, {"step_index": 3, "type": "algebra", "instruction": "Simplify the final expression.", "blank_expression": "Area = ___", "correct_value": "x^2 - 16", "operation_description": "Simplify", "mapped_node_id": "SP"}]', '2026-05-21T12:29:00.344646+00:00', 'Si Aling Nena ay may square na garden kung saan ang haba ng bawat gilid ay x metro. Kung hahabaan niya ang isang side ng 4 na metro at paiikliin ang kabilang side ng 4 na metro, ano ang magiging area ng bagong hugis na garden?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('0bc766fc-c128-4e4c-a391-a2dd9d78da04', 'SP', '(x+5)*(x+2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the dimensions of the rectangular store.", "blank_expression": "Area = (___) * (___)", "correct_value": "x+5, x+2", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "Distribute the terms using the FOIL method.", "blank_expression": "Area = ___", "correct_value": "x^2 + 2x + 5x + 10", "operation_description": "DISTRIBUTE", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Combine the like terms.", "blank_expression": "Area = x^2 + ___ + 10", "correct_value": "7x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "SP"}]', '2026-05-21T12:29:09.414185+00:00', 'Mang Jose is expanding his rectangular sari-sari store space. If the new length is (x + 5) meters and the new width is (x + 2) meters, what is the total area of his expanded store in square meters?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('aa247fa6-bdd4-4879-8e7b-6b00936baeb5', 'SP', '(2x+3)*(x-1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga dimensions ng parihaba mula sa problema.", "blank_expression": "Area = (2x + 3) * (x - 1) = ___", "correct_value": "(2x + 3)(x - 1)", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang FOIL method upang i-multiply ang mga terms.", "blank_expression": "2x^2 + ___ + 3x - 3", "correct_value": "-2x", "operation_description": "DISTRIBUTE", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga like terms na -2x at 3x.", "blank_expression": "2x^2 + ___ - 3", "correct_value": "x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "SP"}]', '2026-05-21T12:29:19.685166+00:00', 'Si Aling Nena ay may maliit na sari-sari store kung saan ang haba ng isang parihabang lalagyan ng sitsirya ay (2x+3) na sentimetro at ang lapad nito ay (x-1) na sentimetro. Ano ang magiging kabuuang area o lawak ng ibabaw ng lalagyan na ito sa pamamagitan ng pag-multiply ng mga expression?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('463fd9b9-46e5-4ac4-93bf-8f1f00802ba8', 'SP', '(x-3)^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang expression para sa area ng bagong garden na may side na (x-3).", "blank_expression": "Area = (x-3)^___", "correct_value": "2", "operation_description": "Identify the variable", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "I-expand ang (x-3)^2 gamit ang square of a binomial rule (a-b)^2 = a^2 - 2ab + b^2.", "blank_expression": "x^2 - ___ + 9", "correct_value": "6x", "operation_description": "Expand the binomial", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang huling sagot.", "blank_expression": "Area = ___", "correct_value": "x^2-6x+9", "operation_description": "Simplify", "mapped_node_id": "SP"}]', '2026-05-21T12:29:28.597840+00:00', 'Si Aling Nena ay may square-shaped na lote na may haba na x metro. Nagbawas siya ng 3 metro sa gilid nito para gawing daanan, kaya naging (x-3) metro na ang bawat side ng natitirang garden.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('a4197e86-9579-45d6-bdf8-767daeef2d1d', 'SP', '(x+1)*(x+6)', '[{"step_index": 0, "type": "variable_id", "instruction": "Isulat ang area ng plot gamit ang formula na Area = length * width.", "blank_expression": "Area = (___) * (___)", "correct_value": "x+6, x+1", "operation_description": "Write the equation", "mapped_node_id": "SP"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang mga terms gamit ang FOIL method.", "blank_expression": "Area = ___ + 6x + 1x + 6", "correct_value": "x^2", "operation_description": "DISTRIBUTE", "mapped_node_id": "SP"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga like terms na 6x at 1x.", "blank_expression": "Area = x^2 + ___ + 6", "correct_value": "7x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "SP"}]', '2026-05-21T12:29:37.588352+00:00', 'Si Aling Nena ay nagbebenta ng rectangular na garden plots sa kanyang farm. Ang haba ng plot ay x+6 na metro at ang lapad nito ay x+1 na metro.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('17dd38a9-b17d-4c2e-911b-91b17ad86ad4', 'FP', 'x^2 + 5*x + 6', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang expression na kailangang i-factor.", "blank_expression": "___ = x^2 + 5x + 6", "correct_value": "Area", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "Maghanap ng dalawang numero na ang product ay 6 at ang sum ay 5.", "blank_expression": "(x + ___)(x + ___)", "correct_value": "2, 3", "operation_description": "Factoring the quadratic trinomial", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang final factored form ng expression.", "blank_expression": "x^2 + 5x + 6 = ___", "correct_value": "(x + 2)(x + 3)", "operation_description": "Final Factored Form", "mapped_node_id": "FP"}]', '2026-05-21T12:29:47.672796+00:00', 'Si Aling Nena ay nag-aayos ng kanyang sari-sari store at kailangan niyang kalkulahin ang sukat ng bagong lalagyan ng mga kendi. Ang area ng lalagyan ay kinakatawan ng expression na x^2 + 5x + 6, kung saan ang x ay ang base unit ng sukat. Ano ang mga factor ng expression na ito upang malaman ang length at width ng lalagyan?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('225a4336-def6-472f-baf7-af6195d7a368', 'FP', 'x^2 - 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang expression para sa natirang area ng lote.", "blank_expression": "Area = ___", "correct_value": "x^2 - 4", "operation_description": "Write the equation", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "I-identify ang square root ng bawat term sa difference of two squares.", "blank_expression": "x^2 - 4 = (x)^2 - (___)^2", "correct_value": "2", "operation_description": "Identify the roots", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Gamitin ang pattern na (a-b)(a+b) para i-factor ang expression.", "blank_expression": "x^2 - 4 = (x - 2)(___)", "correct_value": "x + 2", "operation_description": "Factor the expression", "mapped_node_id": "FP"}]', '2026-05-21T12:29:56.407337+00:00', 'Si Aling Nena ay may isang square na lote na may area na x^2 square meters, ngunit kailangan niyang bawasan ang lawak nito ng 4 square meters para sa daanan ng mga mamimili. Isulat ang expression para sa natirang area ng lote at i-factor ito upang malaman ang mga dimensyon nito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('2c0a7ce9-2561-4b8a-a67a-1aa85a241a9b', 'FP', '2*x^2 + 4*x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang greatest common factor (GCF) ng 2x^2 at 4x.", "blank_expression": "GCF = ___", "correct_value": "2x", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor out ang GCF na 2x mula sa expression.", "blank_expression": "2x^2 + 4x = 2x(___ + 2)", "correct_value": "x", "operation_description": "Factor the expression", "mapped_node_id": "FP"}]', '2026-05-21T12:30:05.612150+00:00', 'Si Aling Nena ay may garden na ang area ay kinakatawan ng expression na 2x^2 + 4x square meters. Gusto niyang malaman ang mga sukat ng haba at lapad ng kanyang garden sa pamamagitan ng pag-factor ng expression na ito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('cafc4723-9507-4488-b115-ba6d97109c1d', 'FP', 'x^2 - 9', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang square root ng x^2 at 9 upang magamit sa difference of two squares.", "blank_expression": "x^2 - 9 = (___ - 3)(___ + 3)", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang expression gamit ang difference of two squares formula.", "blank_expression": "x^2 - 9 = (x - 3)(___)", "correct_value": "x + 3", "operation_description": "Factor the expression", "mapped_node_id": "FP"}]', '2026-05-21T12:30:13.794986+00:00', 'Si Aling Nena ay may square na lote sa tabi ng kanyang sari-sari store na may area na x^2 - 9 square meters. Gusto niyang malaman ang mga dimensyon ng lote na ito para makapagtayo siya ng bagong lagayan ng paninda.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d5da2d88-c2e4-4676-9011-f8fcf6dfc79a', 'FP', 'x^2 + 7*x + 12', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang constant term at ang coefficient ng middle term.", "blank_expression": "x^2 + 7x + 12; constant = ___, middle coefficient = 7", "correct_value": "12", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "Maghanap ng dalawang numero na ang product ay 12 at ang sum ay 7.", "blank_expression": "factors of 12 that add up to 7 are ___ and 4", "correct_value": "3", "operation_description": "Find factors", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang factored form ng polynomial.", "blank_expression": "x^2 + 7x + 12 = (x + 3)(x + ___)", "correct_value": "4", "operation_description": "Write factored form", "mapped_node_id": "FP"}]', '2026-05-21T12:30:22.392149+00:00', 'Si Aling Nena ay may garden plot na hugis parisukat kung saan ang area ay maipapahayag ng x^2 + 7x + 12 square meters. Tulungan si Aling Nena na mahanap ang haba at lapad ng kanyang garden plot sa pamamagitan ng pag-factor ng expression na ito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('3674ff01-dc63-471d-b1ac-62519dd6673a', 'FP', 'x^2 - 6*x + 9', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression na nagrerepresenta sa area ng square garden.", "blank_expression": "Area = ___", "correct_value": "x^2 - 6x + 9", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic trinomial sa pamamagitan ng paghahanap ng dalawang numero na ang product ay 9 at ang sum ay -6.", "blank_expression": "x^2 - 6x + 9 = (x - 3)(___)", "correct_value": "x - 3", "operation_description": "Factoring the perfect square trinomial", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang factor sa anyong exponent.", "blank_expression": "x^2 - 6x + 9 = (x - 3)^___", "correct_value": "2", "operation_description": "Writing as a square of a binomial", "mapped_node_id": "FP"}]', '2026-05-21T12:30:33.054271+00:00', 'Si Aling Nena ay may square na garden sa harap ng kanyang sari-sari store na may area na x^2 - 6x + 9 square meters. Ano ang sukat ng bawat gilid ng kanyang garden?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('0d4c59cb-83b2-4309-841b-273461016257', 'FP', '3*x^2 + 6*x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang GCF (Greatest Common Factor) ng mga term na 3x^2 at 6x.", "blank_expression": "GCF = ___", "correct_value": "3x", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "Ilabas ang GCF mula sa expression.", "blank_expression": "3x^2 + 6x = ___(x + 2)", "correct_value": "3x", "operation_description": "Factor the expression", "mapped_node_id": "FP"}]', '2026-05-21T12:30:41.503200+00:00', 'Si Aling Nena ay may isang rectangular na garden sa likod ng kanyang sari-sari store na ang area ay may sukat na 3x^2 + 6x square meters. Gamitin ang factoring upang mahanap ang mga dimensyon (length at width) ng garden na ito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('40c14778-98c2-4bb2-96d6-891a97df7f4c', 'FP', 'x^2 + 2*x - 8', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang quadratic trinomial na dapat i-factor.", "blank_expression": "Area = ___", "correct_value": "x^2 + 2x - 8", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "Hanapin ang dalawang numero na ang product ay -8 at ang sum ay 2.", "blank_expression": "(x + 4)(x - 2) = ___", "correct_value": "x^2 + 2x - 8", "operation_description": "Factor the quadratic trinomial", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang kabilang side ng garden.", "blank_expression": "Side = ___", "correct_value": "x + 4", "operation_description": "Determine the remaining factor", "mapped_node_id": "FP"}]', '2026-05-21T12:30:50.261775+00:00', 'Si Aling Nena ay nagdisenyo ng isang rectangular na garden sa tapat ng kanyang sari-sari store. Ang area ng garden ay kinakatawan ng expression na x^2 + 2x - 8 square meters, kung saan ang isa sa mga side nito ay may habang (x - 2) meters. Ano ang magiging expression para sa kabilang side ng kanyang garden?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d0da72c3-1727-441e-b5d3-053c397c72aa', 'FP', 'x^2 - 16', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang expression para sa lawak ng lote.", "blank_expression": "___", "correct_value": "x^2 - 16", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "Isulat ang 16 bilang square ng isang numero.", "blank_expression": "x^2 - ___", "correct_value": "4^2", "operation_description": "Rewrite as difference of two squares", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "I-factor ang difference of two squares.", "blank_expression": "(x + 4)(___)", "correct_value": "x - 4", "operation_description": "Factor the expression", "mapped_node_id": "FP"}]', '2026-05-21T12:30:59.752837+00:00', 'Si Aling Nena ay may lote na hugis parisukat na may lawak na x^2 square meters, ngunit kailangan niyang bawasan ang isang bahagi nito ng 16 square meters para sa daanan. Ilahad ang lawak ng natitirang lote sa pamamagitan ng pag-factor ng expression na x^2 - 16.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('26657c59-62e0-498f-a07a-cb0925b282d6', 'FP', 'x^2 + 4*x + 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the expression representing the area of the square.", "blank_expression": "Area = ___", "correct_value": "x^2 + 4x + 4", "operation_description": "Identify the variable", "mapped_node_id": "FP"}, {"step_index": 1, "type": "algebra", "instruction": "Recognize that the expression is a perfect square trinomial of the form a^2 + 2ab + b^2, where a = x and b = 2. Factor the expression as (x + ___)^2.", "blank_expression": "(x + ___)^2", "correct_value": "2", "operation_description": "Factor the perfect square trinomial", "mapped_node_id": "FP"}]', '2026-05-21T12:31:07.764406+00:00', 'Aling Nena wants to tile a square area in front of her sari-sari store to make a small waiting spot. If the area of the square space is represented by the expression x^2 + 4x + 4 square meters, what is the length of one side of the square?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('1a5b4799-0a07-4abf-bcef-c08516f39275', 'RPP', '3/4 = x/8', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa dami ng baso ng malagkit na bigas.", "blank_expression": "x = ___", "correct_value": "dami ng baso ng malagkit", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang ratio ng malagkit sa gata base sa problema.", "blank_expression": "3/4 = x/8", "correct_value": "3/4 = x/8", "operation_description": "Write the equation", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "I-cross multiply ang mga ratio upang makuha ang equation.", "blank_expression": "4 * x = ___", "correct_value": "3 * 8", "operation_description": "Cross multiplication", "mapped_node_id": "RPP"}, {"step_index": 3, "type": "algebra", "instruction": "I-multiply ang mga numero sa kanang bahagi.", "blank_expression": "4 * x = ___", "correct_value": "24", "operation_description": "Simplify", "mapped_node_id": "RPP"}, {"step_index": 4, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 4 para makuha ang x.", "blank_expression": "x = ___", "correct_value": "6", "operation_description": "Division", "mapped_node_id": "RPP"}]', '2026-05-21T12:31:18.815879+00:00', 'Si Aling Nena ay nagluluto ng kakanin kung saan ang bawat 3 baso ng malagkit na bigas ay nangangailangan ng 4 na tasa ng gata. Kung gagamit siya ng 8 tasa ng gata para sa isang malaking batch, ilang baso ng malagkit na bigas ang kailangan niya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('291f6182-12ef-4f21-8100-3c6ca0fd947e', 'RPP', '2/5 = 4/x', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the variable x, which represents the total cost in pesos for 4 pieces of pandesal.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "Cross-multiply the ratios to solve for x.", "blank_expression": "2 * x = ___", "correct_value": "20", "operation_description": "Cross-multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "Divide both sides by 2 to isolate x.", "blank_expression": "x = ___", "correct_value": "10", "operation_description": "Division property of equality", "mapped_node_id": "RPP"}]', '2026-05-21T12:31:27.286809+00:00', 'Aling Nena sells 2 pieces of pandesal for 5 pesos at her sari-sari store. If Mang Jun wants to buy 4 pieces of pandesal, how many pesos (x) does he need to pay?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('6695c1eb-6339-4586-b39a-c86d6e9c709a', 'RPP', 'x/3 = 6/9', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the variable that represents the cost of 1 piece of pancit canton.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "Cross-multiply the terms to begin solving for x.", "blank_expression": "9 * x = ___", "correct_value": "18", "operation_description": "Cross-multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "Divide both sides by 9 to isolate x.", "blank_expression": "x = ___", "correct_value": "2", "operation_description": "Division property of equality", "mapped_node_id": "RPP"}]', '2026-05-21T12:31:36.296808+00:00', 'Aling Nena sells 3 pieces of pancit canton for 6 pesos. If you want to know how much 1 piece of pancit canton costs, you can use the ratio x over 3 equals 6 over 9, where x represents the cost of 1 piece.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('26717832-0a1d-4b2d-893f-ee1659680964', 'RPP', '5/x = 10/14', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa presyo ng 5 kendi.", "blank_expression": "___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang cross-multiplication upang makuha ang equation.", "blank_expression": "10 * x = ___", "correct_value": "5 * 14", "operation_description": "Cross-multiply", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "I-multiply ang mga numero sa kanang bahagi.", "blank_expression": "10 * x = ___", "correct_value": "70", "operation_description": "Multiply constants", "mapped_node_id": "RPP"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 10 para makuha ang x.", "blank_expression": "x = ___", "correct_value": "7", "operation_description": "Division property of equality", "mapped_node_id": "RPP"}]', '2026-05-21T12:31:45.543090+00:00', 'Si Aling Nena ay nagtitinda ng kendi sa kanyang sari-sari store kung saan ang 5 kendi ay nagkakahalaga ng x pesos. Kung ang 10 kendi naman ay nagkakahalaga ng 14 pesos, ilang pesos ang halaga ng 5 kendi?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('a678826b-5705-4ae0-8deb-0e6104ee5cb8', 'RPP', '1/2 = x/10', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the number of squid balls as the unknown variable x.", "blank_expression": "1/2 = x/10", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "Cross-multiply the values to set up the equation.", "blank_expression": "2 * x = ___", "correct_value": "10", "operation_description": "Cross multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "Divide both sides by 2 to solve for x.", "blank_expression": "x = ___", "correct_value": "5", "operation_description": "Division", "mapped_node_id": "RPP"}]', '2026-05-21T12:31:53.863026+00:00', 'Mang Jose sells fishballs where 1 out of every 2 pieces is a squid ball. If he has 10 pieces of fishballs in his cart, how many squid balls are there?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('db147c96-7fa3-4632-a17e-b2e54975753f', 'RPP', 'x/6 = 3/9', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the variable x as the total cost for 6 pieces of candy.", "blank_expression": "x = ___", "correct_value": "total cost", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "Multiply both sides by 6 to isolate x.", "blank_expression": "x = (3/9) * ___", "correct_value": "6", "operation_description": "Multiply both sides", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "Simplify the fraction and solve for x.", "blank_expression": "x = ___", "correct_value": "2", "operation_description": "Simplify", "mapped_node_id": "RPP"}]', '2026-05-21T12:32:02.066711+00:00', 'Aling Nena sells 3 pieces of candy for 9 pesos in her sari-sari store. If you want to buy 6 pieces of candy at the same rate, how many pesos will you pay? Let x be the total cost for 6 pieces of candy.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('cd8a3260-ae4a-4e16-a927-e358717d6a27', 'RPP', '4/5 = x/25', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa bilang ng kutsara ng asukal na kailangan.", "blank_expression": "x = ___", "correct_value": "bilang ng kutsara ng asukal", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "I-cross multiply ang ratio para mahanap ang halaga ng x.", "blank_expression": "5 * x = 4 * 25", "correct_value": "100", "operation_description": "Cross multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 5 para makuha ang x.", "blank_expression": "x = 100 / 5", "correct_value": "20", "operation_description": "Division", "mapped_node_id": "RPP"}]', '2026-05-21T12:32:10.814150+00:00', 'Si Aling Nena ay nagbebenta ng palamig kung saan ang ratio ng baso ng juice sa bawat 5 baso ay may 4 na kutsara ng asukal. Kung gagawa siya ng 25 baso ng juice, ilang kutsara ng asukal (x) ang kailangan niya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('8b2d39b5-bb03-4bdb-a449-caea1732acb0', 'RPP', '2/x = 6/15', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable x sa equation.", "blank_expression": "2 / ___ = 6 / 15", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "I-cross multiply ang equation.", "blank_expression": "6 * x = ___", "correct_value": "30", "operation_description": "Cross multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 6 para makuha ang x.", "blank_expression": "x = ___", "correct_value": "5", "operation_description": "Division property", "mapped_node_id": "RPP"}]', '2026-05-21T12:32:19.194944+00:00', 'Si Aling Nena ay nagtitinda ng kendi sa kanyang sari-sari store kung saan ang 2 pirasong kendi ay nagkakahalaga ng x pesos. Kung ang 6 na piraso ng parehong kendi ay nagkakahalaga ng 15 pesos, gaano ang halaga ng bawat 2 piraso nito?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('c8e782f5-fcfb-4a5f-b609-2ef3f34b6dc1', 'RPP', 'x/4 = 9/12', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable x na kumakatawan sa halaga ng 4 na piraso ng pandesal.", "blank_expression": "x / 4 = 9 / 12", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "I-cross multiply ang mga ratio upang mahanap ang halaga ng x.", "blank_expression": "12 * x = ___", "correct_value": "36", "operation_description": "Cross multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 12 upang makuha ang x.", "blank_expression": "x = ___", "correct_value": "3", "operation_description": "Division", "mapped_node_id": "RPP"}]', '2026-05-21T12:32:30.081132+00:00', 'Si Aling Nena ay nagbebenta ng pandesal sa presyong 9 na piraso para sa 12 piso. Kung bibili si Juan ng 4 na piraso ng pandesal, magkano ang dapat niyang ibayad?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('00248ae0-fe62-482f-81ed-0f99ae2db6cb', 'RPP', '3/x = 9/21', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa presyo ng 3 kendi.", "blank_expression": "3 / ___ = 9 / 21", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RPP"}, {"step_index": 1, "type": "algebra", "instruction": "I-cross multiply ang mga ratio.", "blank_expression": "9 * x = ___", "correct_value": "3 * 21", "operation_description": "Cross multiplication", "mapped_node_id": "RPP"}, {"step_index": 2, "type": "algebra", "instruction": "I-multiply ang mga numero sa kanang bahagi.", "blank_expression": "9 * x = ___", "correct_value": "63", "operation_description": "Multiplication", "mapped_node_id": "RPP"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 9 para makuha ang x.", "blank_expression": "x = ___", "correct_value": "63 / 9", "operation_description": "Division", "mapped_node_id": "RPP"}, {"step_index": 4, "type": "algebra", "instruction": "Ibigay ang huling sagot.", "blank_expression": "x = ___", "correct_value": "7", "operation_description": "Simplify", "mapped_node_id": "RPP"}]', '2026-05-21T12:32:39.873071+00:00', 'Si Aling Nena ay nagtitinda ng kendi sa kanyang sari-sari store kung saan ang 3 pirasong kendi ay nagkakahalaga ng x pesos. Kung ang 9 na piraso ng parehong kendi ay nagkakahalaga ng 21 pesos, ano ang halaga ng x?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('1e3a15ff-82a7-4acf-894b-bc80c99959d7', 'AE', '2*x + 3', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable x na kumakatawan sa bilang ng pandesal.", "blank_expression": "x = ___", "correct_value": "bilang ng pandesal", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "I-substitute ang halaga ng x kung bibili ka ng 5 pandesal.", "blank_expression": "2(5) + 3 = ___", "correct_value": "13", "operation_description": "Evaluate the expression", "mapped_node_id": "AE"}]', '2026-05-21T12:32:48.042323+00:00', 'Si Aling Nena ay nagbebenta ng bawat piraso ng pandesal sa halagang 2 piso. Kung bibili ka ng x na piraso ng pandesal at magdadagdag ng 3 piso para sa pambayad sa plastic bag, magkano ang kabuuang babayaran mo?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('3da8ba52-b1ad-4d7f-8a5b-45e0b2fa9cbf', 'AE', '3*x - 2*x + 5', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa timbang ng bigas sa bawat kilo.", "blank_expression": "x = ___", "correct_value": "timbang ng isang kilong bigas", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na terms (like terms).", "blank_expression": "___ + 5", "correct_value": "x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang huling anyo ng expression sa pamamagitan ng pagtanggal ng coefficient na 1.", "blank_expression": "___ + 5", "correct_value": "x + 5", "operation_description": "REMOVE_MULTIPLYING_BY_ONE", "mapped_node_id": "AE"}]', '2026-05-21T12:33:05.907236+00:00', 'Si Aling Nena ay may 3 kilong bigas at nagbenta siya ng 2 kilong bigas sa isang customer. Kung may dagdag na 5 kilong bigas pa siya sa kanyang bodega, ilang kilo ng bigas ang natitira sa kanya kung ang x ay ang timbang ng isang kilong bigas?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('0c8cf1cd-d32b-4528-a8f7-16d4eea075df', 'AE', '4*(x+2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa bilang ng kendi sa bawat supot.", "blank_expression": "x = ___", "correct_value": "bilang ng kendi sa bawat supot", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang 4 sa loob ng parenthesis.", "blank_expression": "4(x + 2) = ___", "correct_value": "4x + 8", "operation_description": "Distribute", "mapped_node_id": "AE"}]', '2026-05-21T12:33:13.938456+00:00', 'Si Aling Nena ay bumili ng 4 na supot ng kendi para sa kanyang sari-sari store. Ang bawat supot ay naglalaman ng ''x'' piraso ng kendi at dagdag na 2 pirasong libre. Ilang kabuuang piraso ng kendi ang natanggap ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d0ae08cc-c499-49f3-8b8f-e8a85e02c940', 'AE', 'x + 2*x + 3*x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa bilang ng notebook ng bawat anak.", "blank_expression": "x = ___", "correct_value": "bilang ng notebook", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na terms (like terms) sa expression.", "blank_expression": "x + 2x + 3x = ___", "correct_value": "6x", "operation_description": "Add polynomial terms", "mapped_node_id": "AE"}]', '2026-05-21T12:33:27.750406+00:00', 'Si Aling Nena ay bumili ng mga notebook para sa kanyang mga anak. Ang unang anak ay nangailangan ng x na notebook, ang pangalawa ay nangailangan ng 2x, at ang pangatlo ay nangailangan ng 3x na notebook.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b028bd12-fe13-48b8-8208-67cb74e6b5f3', 'AE', '5*x - 3 + 2*x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa presyo ng bawat notebook.", "blank_expression": "x = ___", "correct_value": "presyo ng bawat notebook", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na terms (like terms) na may variable na x.", "blank_expression": "___ - 3", "correct_value": "7x", "operation_description": "Combine like terms", "mapped_node_id": "AE"}]', '2026-05-21T12:33:35.645628+00:00', 'Si Aling Nena ay bumili ng 5 notebooks para sa kanyang anak at 2 notebooks pa para sa kanyang pamangkin sa halagang x pesos bawat isa. Kung binigyan niya ang tindera ng diskwento na 3 pesos sa kabuuang bayad, ano ang algebraic expression para sa kanyang kabuuang gastos?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e5408c24-6b11-4bc9-b93e-f039d53a54bd', 'AE', 'x^2 + 2*x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang halaga ng x base sa problema.", "blank_expression": "x = ___", "correct_value": "3", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "I-substitute ang x = 3 sa expression na x^2 + 2x.", "blank_expression": "(___)^2 + 2(3)", "correct_value": "3", "operation_description": "Substitution", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square ng 3.", "blank_expression": "___ + 2(3)", "correct_value": "9", "operation_description": "Exponentiation", "mapped_node_id": "PE"}, {"step_index": 3, "type": "algebra", "instruction": "I-multiply ang 2 at 3.", "blank_expression": "9 + ___", "correct_value": "6", "operation_description": "Multiplication", "mapped_node_id": "PO"}, {"step_index": 4, "type": "algebra", "instruction": "Kunin ang kabuuang sum.", "blank_expression": "___", "correct_value": "15", "operation_description": "Addition", "mapped_node_id": "AE"}]', '2026-05-21T12:33:46.189881+00:00', 'Si Aling Nena ay nagpaplano ng hugis-parisukat na garden sa harap ng kanyang sari-sari store kung saan ang haba ng bawat gilid ay x metro. Kung ang kabuuang area ng garden ay x^2 at magdadagdag siya ng extension na may sukat na 2x metro kuwadrado, ano ang magiging kabuuang area ng garden kung ang x ay 3 metro?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('1ecddcfc-5d9d-40af-bb51-bc4fba8a9ea3', 'AE', '3*(x+1) + 2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa presyo ng bawat notebook.", "blank_expression": "x = ___", "correct_value": "presyo ng bawat notebook", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang 3 sa loob ng parenthesis.", "blank_expression": "___ + 3 + 2", "correct_value": "3x", "operation_description": "DISTRIBUTE", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga constant terms.", "blank_expression": "3x + ___", "correct_value": "5", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "AE"}]', '2026-05-21T12:33:54.627455+00:00', 'Si Aling Nena ay bumili ng tatlong notebook para sa kanyang anak at nagbayad din siya ng 2 pesos para sa plastic cover. Kung ang bawat notebook ay nagkakahalaga ng x pesos at may dagdag na 1 piso para sa bawat notebook dahil sa brand, magkano ang kabuuang gastos ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('962eccbc-d909-400e-8893-c80624570e4d', 'AE', '2*x^2 - x', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa bilang ng mga eco-bag na ibinebenta.", "blank_expression": "x = ___", "correct_value": "5", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "I-substitute ang value ng x sa expression.", "blank_expression": "2(___)^2 - 5", "correct_value": "5", "operation_description": "Substitution", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "I-evaluate ang exponent.", "blank_expression": "2(___) - 5", "correct_value": "25", "operation_description": "Evaluate exponent", "mapped_node_id": "PE"}, {"step_index": 3, "type": "algebra", "instruction": "I-multiply ang 2 sa 25.", "blank_expression": "___ - 5", "correct_value": "50", "operation_description": "Multiplication", "mapped_node_id": "PO"}, {"step_index": 4, "type": "algebra", "instruction": "I-subtract ang 5 mula sa 50 para makuha ang final answer.", "blank_expression": "___", "correct_value": "45", "operation_description": "Subtraction", "mapped_node_id": "AE"}]', '2026-05-21T12:34:03.941437+00:00', 'Si Aling Nena ay nagbebenta ng mga eco-bag sa kanyang tindahan kung saan ang kita ay kinakalkula gamit ang formula na 2x^2 - x. Kung makakabenta siya ng 5 eco-bag ngayong araw, magkano ang magiging kabuuang kita niya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('f2c9cf0b-3c8e-4f24-ae5e-09d654f897a1', 'AE', '4*x + x - 2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa presyo ng bawat notebook.", "blank_expression": "x = ___", "correct_value": "presyo ng bawat notebook", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na term (like terms) sa expression.", "blank_expression": "___ - 2", "correct_value": "5x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "AE"}]', '2026-05-21T12:34:13.725050+00:00', 'Si Aling Nena ay bumili ng 4 na pirasong notebook at dagdag pa na isang notebook para sa kanyang anak. Kung ang bawat notebook ay nagkakahalaga ng x pesos at siya ay binigyan ng discount na 2 pesos sa kabuuang bayad, ano ang algebraic expression para sa kanyang kabuuang gastos?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d21e4143-e26c-4bca-a49a-3908add72f3f', 'L1V', '2*x + 3 = 7', '[{"step_index": 0, "type": "variable_id", "instruction": "I-representa ang presyo ng bawat notebook bilang x.", "blank_expression": "2x + 3 = 7", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "I-subtract ang 3 sa magkabilang panig ng equation.", "blank_expression": "2x = 7 - ___", "correct_value": "3", "operation_description": "Addition Property of Equality", "mapped_node_id": "PE"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang kanang panig (7 - 3).", "blank_expression": "2x = ___", "correct_value": "4", "operation_description": "Simplify", "mapped_node_id": "LE"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 2 para makuha ang x.", "blank_expression": "x = 4 / ___", "correct_value": "2", "operation_description": "Division Property of Equality", "mapped_node_id": "PD"}, {"step_index": 4, "type": "algebra", "instruction": "Isulat ang huling sagot.", "blank_expression": "x = ___", "correct_value": "2", "operation_description": "Final Answer", "mapped_node_id": "LE"}]', '2026-05-21T12:34:23.012031+00:00', 'Bumili si Maria ng 2 notebook na pareho ang presyo at isang ballpen na nagkakahalaga ng 3 piso. Kung ang kabuuang binayaran niya ay 7 piso, magkano ang presyo ng bawat notebook?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('5ad57bcb-148c-4791-83c2-71280693e6ef', 'L1V', 'x - 4 = 10', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x bilang kabuuang bilang ng kendi sa simula. Isulat ang equation base sa sitwasyon.", "blank_expression": "___ = 10", "correct_value": "x - 4", "operation_description": "Write the equation", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "Magdagdag ng 4 sa magkabilang panig ng equation.", "blank_expression": "x = 10 ___", "correct_value": "+ 4", "operation_description": "Addition Property of Equality", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang final value ng x.", "blank_expression": "x = ___", "correct_value": "14", "operation_description": "Simplify", "mapped_node_id": "L1V"}]', '2026-05-21T12:34:37.178804+00:00', 'Si Aling Nena ay may ilang piraso ng kendi sa loob ng garapon. Matapos siyang kumuha ng 4 na piraso para ibigay sa kanyang pamangkin, may natira na lamang na 10 piraso sa loob ng garapon.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e7f1c1aa-a9be-4a74-805b-dba66c403ecc', 'L1V', '3*x = 15', '[{"step_index": 0, "type": "variable_id", "instruction": "I-representa ang presyo ng bawat notebook bilang variable na x.", "blank_expression": "3 * x = 15", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "I-divide ang magkabilang panig ng equation sa 3 para makuha ang value ng x.", "blank_expression": "x = 15 / __", "correct_value": "3", "operation_description": "Divide both sides", "mapped_node_id": "L1V"}, {"step_index": 2, "type": "algebra", "instruction": "I-compute ang huling sagot.", "blank_expression": "x = __", "correct_value": "5", "operation_description": "Simplify", "mapped_node_id": "L1V"}]', '2026-05-21T12:34:45.650125+00:00', 'Bumili si Aling Nena ng 3 pirasong notebook sa sari-sari store para sa kanyang anak sa halagang 15 piso. Magkano ang halaga ng bawat isang notebook kung pare-pareho ang presyo nito?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('af45bfc5-0229-48ac-bc5f-24a3e3ffab48', 'L1V', 'x/2 = 6', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x na maging kabuuang bilang ng mga kendi.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang equation batay sa sitwasyon.", "blank_expression": "___ = 6", "correct_value": "x/2", "operation_description": "Write the equation", "mapped_node_id": "L1V"}, {"step_index": 2, "type": "algebra", "instruction": "I-multiply ang magkabilang panig ng 2 upang makuha ang x.", "blank_expression": "x = 6 * ___", "correct_value": "2", "operation_description": "Multiplication Property of Equality", "mapped_node_id": "PE"}, {"step_index": 3, "type": "algebra", "instruction": "I-calculate ang huling sagot.", "blank_expression": "x = ___", "correct_value": "12", "operation_description": "Simplify", "mapped_node_id": "LE"}]', '2026-05-21T12:34:54.360632+00:00', 'Si Aling Nena ay naghahati ng isang pack ng kendi sa dalawang magkasing-dami na grupo para sa kanyang mga anak. Kung ang bawat grupo ay may 6 na piraso ng kendi, ilan lahat ang kendi sa isang pack?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e6fb18cc-aef5-413a-a824-fd342f8f49fb', 'L1V', '5*x - 2 = 13', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x na maging presyo ng isang notebook. Isulat ang equation base sa sitwasyon.", "blank_expression": "5*x - 2 = 13", "correct_value": "5*x - 2 = 13", "operation_description": "Write the equation", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "Ilipat ang -2 sa kabilang panig ng equation sa pamamagitan ng pag-add ng 2 sa magkabilang panig.", "blank_expression": "5*x = 13 + ___", "correct_value": "2", "operation_description": "Addition Property of Equality", "mapped_node_id": "PE"}, {"step_index": 2, "type": "algebra", "instruction": "Pag-simplify ng kanang bahagi ng equation.", "blank_expression": "5*x = ___", "correct_value": "15", "operation_description": "Simplify", "mapped_node_id": "OI"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 5 upang makuha ang halaga ng x.", "blank_expression": "x = 15 / ___", "correct_value": "5", "operation_description": "Division Property of Equality", "mapped_node_id": "PD"}, {"step_index": 4, "type": "algebra", "instruction": "Ibigay ang pinal na sagot.", "blank_expression": "x = ___", "correct_value": "3", "operation_description": "Solution", "mapped_node_id": "LE"}]', '2026-05-21T12:35:04.540382+00:00', 'Si Aling Nena ay bumili ng 5 piraso ng notebook na pareho ang presyo at binawasan niya ang kanyang bayad ng 2 pesos para sa isang discount voucher. Kung ang kabuuang binayaran niya ay 13 pesos, magkano ang presyo ng bawat notebook?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('5f0d1195-5b1a-48f1-853d-8d292fad4dc1', 'L1V', '4*x + 1 = 17', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x na kumatawan sa presyo ng bawat notebook.", "blank_expression": "4x + 1 = 17", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "Ilipat ang 1 sa kabilang panig ng equation sa pamamagitan ng pagbabawas.", "blank_expression": "4x = 17 - ___", "correct_value": "1", "operation_description": "Subtract 1 from both sides", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang kanang bahagi ng equation.", "blank_expression": "4x = ___", "correct_value": "16", "operation_description": "Simplify the expression", "mapped_node_id": "OI"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 4 para makuha ang value ng x.", "blank_expression": "x = 16 / ___", "correct_value": "4", "operation_description": "Divide by 4", "mapped_node_id": "PD"}, {"step_index": 4, "type": "algebra", "instruction": "Isulat ang huling sagot.", "blank_expression": "x = ___", "correct_value": "4", "operation_description": "Final solution", "mapped_node_id": "L1V"}]', '2026-05-21T12:35:14.946011+00:00', 'Si Aling Nena ay bumili ng 4 na pirasong notebook na pare-pareho ang presyo at nagbayad ng dagdag na 1 piso para sa isang plastic cover. Kung ang kabuuang binayaran niya ay 17 piso, magkano ang presyo ng bawat notebook?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('80de56f6-cc53-4776-aea9-34151bf4eeea', 'L1V', 'x + 8 = 15', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kakatawan sa bilang ng kendi na mayroon si Aling Nena noong una.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang equation na nagpapakita ng sitwasyon.", "blank_expression": "___ + 8 = 15", "correct_value": "x", "operation_description": "Write the equation", "mapped_node_id": "L1V"}, {"step_index": 2, "type": "algebra", "instruction": "I-subtract ang 8 sa magkabilang panig ng equation.", "blank_expression": "x = 15 - ___", "correct_value": "8", "operation_description": "Subtraction Property of Equality", "mapped_node_id": "PE"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve ang value ng x.", "blank_expression": "x = ___", "correct_value": "7", "operation_description": "Simplify", "mapped_node_id": "LE"}]', '2026-05-21T12:35:24.498484+00:00', 'Si Aling Nena ay may ilang piraso ng kendi sa isang garapon. Nagdagdag siya ng 8 piraso pa kaya naging 15 ang kabuuang bilang ng kendi sa garapon.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('805256af-3f9e-408d-ad9a-db42324bf591', 'L1V', '2*x - 5 = 9', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x na maging presyo ng bawat kilo ng asukal.", "blank_expression": "2*x - 5 = 9", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "Idagdag ang 5 sa magkabilang panig ng equation.", "blank_expression": "2*x = 9 + ___", "correct_value": "5", "operation_description": "Addition Property of Equality", "mapped_node_id": "PE"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang kanang bahagi.", "blank_expression": "2*x = ___", "correct_value": "14", "operation_description": "Simplify", "mapped_node_id": "SP"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 2.", "blank_expression": "x = ___ / 2", "correct_value": "14", "operation_description": "Division Property of Equality", "mapped_node_id": "FD"}, {"step_index": 4, "type": "algebra", "instruction": "Kunin ang huling sagot.", "blank_expression": "x = ___", "correct_value": "7", "operation_description": "Final result", "mapped_node_id": "L1V"}]', '2026-05-21T12:35:39.211775+00:00', 'Si Aling Nena ay bumili ng dalawang kilo ng asukal na pareho ang presyo bawat kilo. Matapos niyang mabawasan ng 5 piso ang kanyang bayad dahil sa discount, ang kabuuang binayaran niya ay 9 na piso. Magkano ang presyo ng bawat kilo ng asukal?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('f18c0e68-bc77-4209-a409-6cb0b7d11119', 'L1V', '3*x + 4 = 19', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable para sa presyo ng bawat notebook.", "blank_expression": "x = ___", "correct_value": "presyo ng notebook", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang equation base sa sitwasyon.", "blank_expression": "___ = 19", "correct_value": "3x + 4", "operation_description": "Write the equation", "mapped_node_id": "L1V"}, {"step_index": 2, "type": "algebra", "instruction": "I-subtract ang 4 mula sa magkabilang panig ng equation.", "blank_expression": "3x = ___", "correct_value": "15", "operation_description": "Subtraction Property of Equality", "mapped_node_id": "SP"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 3 para makuha ang halaga ng x.", "blank_expression": "x = ___", "correct_value": "5", "operation_description": "Division Property of Equality", "mapped_node_id": "PD"}]', '2026-05-21T12:35:48.472642+00:00', 'Si Juan ay bumili ng 3 notebook na may parehong presyo at isang ballpen na nagkakahalaga ng 4 pesos. Kung ang kabuuang binayaran niya ay 19 pesos, magkano ang presyo ng bawat notebook?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('eea01bc2-56ca-4596-a6a2-29474babdc33', 'L1V', 'x/3 = 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x na maging kabuuang bilang ng mga ballpen sa bundle.", "blank_expression": "x / 3 = 4", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "L1V"}, {"step_index": 1, "type": "algebra", "instruction": "I-multiply ang magkabilang panig ng 3 para ma-isolate ang x.", "blank_expression": "x = 4 * ___", "correct_value": "3", "operation_description": "Multiplication Property of Equality", "mapped_node_id": "PE"}, {"step_index": 2, "type": "algebra", "instruction": "I-compute ang huling halaga ng x.", "blank_expression": "x = ___", "correct_value": "12", "operation_description": "Simplify", "mapped_node_id": "LE"}]', '2026-05-21T12:35:57.478588+00:00', 'Si Aling Nena ay naghati ng isang bundle ng ballpen sa 3 magkakatulad na grupo para sa kanyang mga apo. Kung ang bawat grupo ay may 4 na ballpen, ilan lahat ang ballpen sa loob ng bundle?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('fa28f75f-690d-4ad1-abb9-b4a72e638fc8', 'L2V', 'y = 2*x + 1', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga variable: x bilang dami ng kwek-kwek at y bilang kabuuang bayad.", "blank_expression": "y = ___x + ___", "correct_value": "2, 1", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "I-substitute ang halaga ng x para makuha ang y.", "blank_expression": "y = 2(x) + 1", "correct_value": "2x + 1", "operation_description": "Simplify the expression", "mapped_node_id": "LE"}]', '2026-05-21T12:36:05.816338+00:00', 'Si Aling Nena ay nagbebenta ng kwek-kwek kung saan ang halaga ay nakabase sa bilang ng piraso. Kung ang kwek-kwek ay nagkakahalaga ng 2 piso bawat piraso at may dagdag na 1 pisong service charge para sa lalagyan, ilang piso (y) ang babayaran para sa x na dami ng kwek-kwek?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('a20b28ff-c725-42a3-a2c6-09d6e0433e72', 'L2V', '2*x + y = 10', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable para sa bilang ng notebook (x) at ballpen (y) base sa presyo at kabuuang halaga.", "blank_expression": "2(x) + 1(y) = ___", "correct_value": "10", "operation_description": "Write the equation", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "Ihiwalay ang y sa isang panig ng equation.", "blank_expression": "y = ___ - 2x", "correct_value": "10", "operation_description": "Subtract 2x from both sides", "mapped_node_id": "L2V"}]', '2026-05-21T12:36:14.510630+00:00', 'Si Aling Nena ay nagtitinda ng mga school supplies. Ang presyo ng isang notebook ay 2 piso (x) at ang isang ballpen ay 1 piso (y), kung saan ang kabuuang benta niya sa isang customer ay 10 piso. Bumuo ng equation na nagpapakita ng relasyon ng bilang ng notebook at ballpen na binili ng customer.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('2c0bd164-f603-4968-ac99-0ee54b35bdbe', 'L2V', 'y - x = 3', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga variable base sa kwento.", "blank_expression": "x = presyo ng kwek-kwek, y = presyo ng ___", "correct_value": "palamig", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang equation batay sa ibinigay na sitwasyon.", "blank_expression": "___ - x = 3", "correct_value": "y", "operation_description": "Write the equation", "mapped_node_id": "L2V"}, {"step_index": 2, "type": "algebra", "instruction": "Ihiwalay ang variable na y sa pamamagitan ng paglipat ng -x sa kabilang panig.", "blank_expression": "y = ___ + 3", "correct_value": "x", "operation_description": "Addition Property of Equality", "mapped_node_id": "L2V"}]', '2026-05-21T12:36:23.388496+00:00', 'Si Aling Nena ay nagbebenta ng meryenda sa kanyang sari-sari store kung saan ang presyo ng palamig (y) ay laging 3 piso na mas mahal kaysa sa presyo ng kwek-kwek (x). Isulat ang equation na nagpapakita ng relasyon ng presyo ng palamig at kwek-kwek.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('f9aaba5b-1792-4624-a462-d4a4f910318e', 'L2V', '3*x - y = 6', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable para sa bilang ng notebook at presyo ng ballpen.", "blank_expression": "3x - y = 6", "correct_value": "x = bilang ng notebook, y = presyo ng ballpen", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "Ihiwalay ang -y sa pamamagitan ng paglipat ng 3x sa kabilang panig.", "blank_expression": "-y = ___ - 3x", "correct_value": "6", "operation_description": "Subtract 3x from both sides", "mapped_node_id": "L2V"}, {"step_index": 2, "type": "algebra", "instruction": "I-multiply ang buong equation sa -1 para makuha ang value ng y.", "blank_expression": "y = ___", "correct_value": "3x - 6", "operation_description": "Multiply by -1", "mapped_node_id": "L2V"}]', '2026-05-21T12:36:31.927712+00:00', 'Si Aling Nena ay nagtitinda ng mga school supplies. Sa kanyang tindahan, ang presyo ng tatlong notebook (x) na binawasan ng halaga ng isang ballpen (y) ay nagkakahalaga ng anim na piso (6 pesos).') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('fa6e2601-bbb8-4f06-a603-4517728aced5', 'L2V', 'x + 2*y = 8', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga variable para sa bilang ng pandesal (x) at bilang ng palamig (y).", "blank_expression": "x + 2y = ___", "correct_value": "8", "operation_description": "Write the equation", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "I-isolate ang x sa pamamagitan ng paglipat ng 2y sa kabilang panig.", "blank_expression": "x = ___ - 2y", "correct_value": "8", "operation_description": "Subtraction Property of Equality", "mapped_node_id": "L2V"}]', '2026-05-21T12:36:40.446862+00:00', 'Si Aling Nena ay nagbebenta ng combo meal sa kanyang sari-sari store kung saan ang isang pirasong pandesal (x) at dalawang baso ng palamig (y) ay nagkakahalaga ng kabuuang 8 piso. Isulat ang equation na kumakatawan sa kabuuang halaga ng mga produktong ito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('da5536a2-05d2-4548-9d6f-83aceeaf8768', 'L2V', 'y = -x + 5', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable para sa bilang ng nabentang paninda.", "blank_expression": "x = ___", "correct_value": "2", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "I-substitute ang value ng x sa equation.", "blank_expression": "y = -(2) + ___", "correct_value": "5", "operation_description": "Substitution", "mapped_node_id": "L2V"}, {"step_index": 2, "type": "algebra", "instruction": "I-solve ang value ng y.", "blank_expression": "y = ___", "correct_value": "3", "operation_description": "Simplification", "mapped_node_id": "L2V"}]', '2026-05-21T12:36:49.426594+00:00', 'Si Aling Nena ay may 5 pirasong paninda na balak niyang ubusin sa loob ng maghapon. Kung ang x ay bilang ng panindang nabenta at ang y ay bilang ng natitirang paninda, ilan ang matitira kung makabenta siya ng 2 piraso?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('659cfbfa-dba0-4c7c-8e0e-480ff12bba15', 'L2V', '4*x - y = 7', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable x para sa presyo ng bawat ballpen at y para sa discount.", "blank_expression": "4x - y = ___", "correct_value": "7", "operation_description": "Write the equation", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "Ilipat ang 4x sa kabilang panig ng equation.", "blank_expression": "-y = 7 - ___", "correct_value": "4x", "operation_description": "Addition Property of Equality", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "I-multiply ang magkabilang panig sa -1 para makuha ang y.", "blank_expression": "y = ___", "correct_value": "4x - 7", "operation_description": "Multiplication Property of Equality", "mapped_node_id": "PE"}]', '2026-05-21T12:36:58.256958+00:00', 'Si Aling Nena ay bumili ng 4 na piraso ng ballpen na nagkakahalaga ng x pesos bawat isa. Kung ang kabuuang binayaran niya ay nabawasan ng y pesos na discount at ang natira ay 7 pesos, bumuo ng equation para dito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('c3e976b7-49dd-4bc6-952a-d78a1c323227', 'L2V', '2*x + 3*y = 12', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga variable para sa dami ng pandesal at palamig.", "blank_expression": "2x + 3y = 12", "correct_value": "x = dami ng pandesal, y = dami ng palamig", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "I-isolate ang term na may y sa pamamagitan ng paglipat ng 2x sa kanang bahagi.", "blank_expression": "3y = ___", "correct_value": "12 - 2x", "operation_description": "Subtraction Property of Equality", "mapped_node_id": "PE"}, {"step_index": 2, "type": "algebra", "instruction": "I-divide ang buong equation sa 3 para makuha ang value ng y.", "blank_expression": "y = ___", "correct_value": "(12 - 2x) / 3", "operation_description": "Division Property of Equality", "mapped_node_id": "PD"}]', '2026-05-21T12:37:07.084439+00:00', 'Si Aling Nena ay nagbebenta ng combo meal sa kanyang sari-sari store kung saan ang 2 pirasong pandesal (x) at 3 baso ng palamig (y) ay nagkakahalaga ng kabuuang 12 piso. Bumuo ng linear equation upang ipakita ang relasyon ng presyo ng pandesal at palamig base sa kabuuang halagang ito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('f4999037-0e4f-448d-ab41-d2f1d95f88d5', 'L2V', 'y = 3*x - 2', '[{"step_index": 0, "type": "variable_id", "instruction": "I-define ang x bilang bilang ng turon at y bilang kabuuang kita.", "blank_expression": "y = ___x - 2", "correct_value": "3", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "algebra", "instruction": "Kung si Aling Nena ay nakabenta ng 5 piraso ng turon, ilagay ang 5 sa x.", "blank_expression": "y = 3(5) - ___", "correct_value": "2", "operation_description": "Substitute the value", "mapped_node_id": "L2V"}, {"step_index": 2, "type": "algebra", "instruction": "Kalkulahin ang y.", "blank_expression": "y = ___", "correct_value": "13", "operation_description": "Solve for y", "mapped_node_id": "L2V"}]', '2026-05-21T12:37:17.961481+00:00', 'Si Aling Nena ay nagbebenta ng bawat piraso ng turon sa halagang 3 piso, ngunit may bawas na 2 piso ang kabuuang benta niya dahil sa bayad sa plastic bag. Isulat ang equation para sa kabuuang kita (y) kung ang (x) ay ang bilang ng turon na naibenta.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('4e10fb32-9eef-462f-bcd8-0696fc8f0b10', 'L2V', 'x - y = 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang variable para sa bilang ng notebook.", "blank_expression": "x = ___", "correct_value": "bilang ng notebook", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 1, "type": "variable_id", "instruction": "Ibigay ang variable para sa bilang ng ballpen.", "blank_expression": "y = ___", "correct_value": "bilang ng ballpen", "operation_description": "Identify the variable", "mapped_node_id": "L2V"}, {"step_index": 2, "type": "algebra", "instruction": "Ilipat ang -y sa kanang bahagi ng equation.", "blank_expression": "x = ___ + 4", "correct_value": "y", "operation_description": "Addition Property of Equality", "mapped_node_id": "L2V"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang huling anyo ng equation kung saan ang x ay nakahiwalay.", "blank_expression": "x = y + ___", "correct_value": "4", "operation_description": "Simplify", "mapped_node_id": "L2V"}]', '2026-05-21T12:37:29.581145+00:00', 'Si Aling Nena ay nagtitinda ng mga notebook at ballpen sa kanyang sari-sari store. Ang bilang ng notebook (x) ay higit ng 4 kaysa sa bilang ng ballpen (y) na nabenta niya ngayong araw.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b43b849e-7b2c-4c06-bf49-17ff6d5b16fe', 'SLE', 'x + 2*y = 8, x - y = 2', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga variables batay sa kwento.", "blank_expression": "x = ___, y = ___", "correct_value": "bilang ng notebook, bilang ng ballpen", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "algebra", "instruction": "I-isolate ang x sa pangalawang equation.", "blank_expression": "x = ___ + y", "correct_value": "2", "operation_description": "Substitution method", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "I-substitute ang x sa unang equation.", "blank_expression": "(2 + y) + 2y = ___", "correct_value": "8", "operation_description": "Substitution", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve para sa y.", "blank_expression": "3y = ___", "correct_value": "6", "operation_description": "Simplify", "mapped_node_id": "SLE"}, {"step_index": 4, "type": "algebra", "instruction": "Kunin ang halaga ng y.", "blank_expression": "y = ___", "correct_value": "2", "operation_description": "Division", "mapped_node_id": "SLE"}, {"step_index": 5, "type": "algebra", "instruction": "I-substitute ang y sa equation para makuha ang x.", "blank_expression": "x - 2 = ___", "correct_value": "2", "operation_description": "Substitution", "mapped_node_id": "SLE"}, {"step_index": 6, "type": "algebra", "instruction": "Kunin ang halaga ng x.", "blank_expression": "x = ___", "correct_value": "4", "operation_description": "Addition", "mapped_node_id": "SLE"}]', '2026-05-21T12:37:39.312229+00:00', 'Si Aling Nena ay bumili ng ilang pirasong notebook at ballpen sa isang school supplies store. Ang kabuuang bilang ng notebook (x) at dalawang beses ng bilang ng ballpen (y) ay 8, habang ang pagkakaiba ng bilang ng notebook at ballpen ay 2.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('f8b5fb12-6d6d-4714-b36b-e1d12477401b', 'SLE', '2*x - y = 3, x + y = 6', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang x bilang dami ng spiral notebook at y bilang dami ng regular notebook.", "blank_expression": "x + y = ___", "correct_value": "6", "operation_description": "Write the equation", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang dalawang equation gamit ang elimination method (add the equations).", "blank_expression": "3x = ___", "correct_value": "9", "operation_description": "Elimination", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 3 para makuha ang halaga ng x.", "blank_expression": "x = ___", "correct_value": "3", "operation_description": "Division Property of Equality", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-substitute ang x = 3 sa equation na x + y = 6.", "blank_expression": "3 + y = 6, y = ___", "correct_value": "3", "operation_description": "Substitution", "mapped_node_id": "SLE"}]', '2026-05-21T12:37:48.594059+00:00', 'Si Aling Nena ay bumili ng dalawang uri ng notebook sa isang school supply store. Ang kabuuang bilang ng notebook ay 6, at ang kabuuang halaga ng mga ito ay sumusunod sa equation na 2x - y = 3 kung saan ang x ay bilang ng spiral notebook at ang y ay bilang ng regular notebook.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('65c1293e-fa83-4b6d-8414-7dc9b1905448', 'SLE', '3*x + y = 9, x + y = 5', '[{"step_index": 0, "type": "variable_id", "instruction": "I-represent ang x bilang presyo ng notebook at y bilang presyo ng ballpen.", "blank_expression": "x = presyo ng notebook, y = ___", "correct_value": "presyo ng ballpen", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "algebra", "instruction": "I-subtract ang pangalawang equation sa una para ma-eliminate ang y.", "blank_expression": "(3x + y) - (x + y) = 9 - ___", "correct_value": "5", "operation_description": "Subtraction Property of Equality", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang equation para makuha ang halaga ng x.", "blank_expression": "2x = 4, x = ___", "correct_value": "2", "operation_description": "Division Property of Equality", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-substitute ang x = 2 sa x + y = 5 para mahanap ang y.", "blank_expression": "2 + y = 5, y = ___", "correct_value": "3", "operation_description": "Substitution", "mapped_node_id": "SLE"}]', '2026-05-21T12:37:58.347523+00:00', 'Si Aling Nena ay bumili ng 3 notebook at 1 ballpen sa halagang 9 pesos. Bumili rin siya ng 1 notebook at 1 ballpen sa halagang 5 pesos. Magkano ang halaga ng bawat notebook at bawat ballpen?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('a8e4b844-2b20-4278-965c-c0aad7dbc7a2', 'SLE', 'x + y = 7, 2*x - y = 5', '[{"step_index": 0, "type": "variable_id", "instruction": "I-represent ang bilang ng notebook bilang x at ang bilang ng ballpen bilang y.", "blank_expression": "x + y = ___", "correct_value": "7", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang pangalawang equation batay sa sitwasyon.", "blank_expression": "2x - y = ___", "correct_value": "5", "operation_description": "Write the equation", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "I-add ang dalawang equation para ma-eliminate ang y.", "blank_expression": "3x = ___", "correct_value": "12", "operation_description": "Addition Method", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 3 para makuha ang halaga ng x.", "blank_expression": "x = ___", "correct_value": "4", "operation_description": "Division Property", "mapped_node_id": "SLE"}, {"step_index": 4, "type": "algebra", "instruction": "I-substitute ang x = 4 sa unang equation para mahanap ang y.", "blank_expression": "4 + y = 7, y = ___", "correct_value": "3", "operation_description": "Substitution", "mapped_node_id": "SLE"}]', '2026-05-21T12:38:07.807550+00:00', 'Si Aling Nena ay bumili ng kabuuang 7 piraso ng notebook at ballpen para sa kanyang anak sa halagang ilang piso. Kung ang dalawang beses ng bilang ng notebook minus ang bilang ng ballpen ay katumbas ng 5, ilang notebook at ballpen ang kanyang binili?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('07288167-b519-41cc-8bee-178c6b6a557f', 'SLE', '4*x + y = 11, x + y = 5', '[{"step_index": 0, "type": "variable_id", "instruction": "I-representa ang x bilang presyo ng notebook at y bilang presyo ng ballpen.", "blank_expression": "x = \\text{presyo ng notebook}, y = \\text{presyo ng \\_\\_\\_\\_}", "correct_value": "ballpen", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "algebra", "instruction": "I-isolate ang y sa pangalawang equation para magamit ang substitution.", "blank_expression": "y = \\_\\_\\_\\_ - x", "correct_value": "5", "operation_description": "Isolate variable", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "I-substitute ang y sa unang equation (4x + y = 11).", "blank_expression": "4x + (5 - x) = \\_\\_\\_\\_", "correct_value": "11", "operation_description": "Substitution", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-simplify ang equation para mahanap ang x.", "blank_expression": "3x = \\_\\_\\_\\_", "correct_value": "6", "operation_description": "Simplify", "mapped_node_id": "SLE"}, {"step_index": 4, "type": "algebra", "instruction": "I-divide ang magkabilang side para makuha ang presyo ng notebook.", "blank_expression": "x = \\_\\_\\_\\_", "correct_value": "2", "operation_description": "Solve for x", "mapped_node_id": "SLE"}, {"step_index": 5, "type": "algebra", "instruction": "I-substitute ang x=2 sa equation na y = 5 - x para makuha ang presyo ng ballpen.", "blank_expression": "y = 5 - 2 = \\_\\_\\_\\_", "correct_value": "3", "operation_description": "Solve for y", "mapped_node_id": "SLE"}]', '2026-05-21T12:38:17.826704+00:00', 'Bumili si Aling Nena ng 4 na pirasong notebook at 1 pirasong ballpen sa halagang 11 pesos, habang ang kaibigan naman niya ay bumili ng 1 notebook at 1 ballpen sa halagang 5 pesos. Magkano ang presyo ng bawat isang notebook at bawat isang ballpen?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('aaefe900-cedd-414e-b456-e07adef14e8a', 'SLE', '2*x + 3*y = 13, x + y = 5', '[{"step_index": 0, "type": "variable_id", "instruction": "Hayaan ang x bilang bilang ng notebook at y bilang bilang ng ballpen.", "blank_expression": "x + y = ___", "correct_value": "5", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "algebra", "instruction": "Ipahayag ang x sa pamamagitan ng y mula sa ikalawang equation (x = 5 - y).", "blank_expression": "2(5 - y) + 3y = 13", "correct_value": "10 - 2y + 3y = 13", "operation_description": "Substitution", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga katulad na termino.", "blank_expression": "10 + y = ___", "correct_value": "13", "operation_description": "Simplify", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve para sa y.", "blank_expression": "y = ___", "correct_value": "3", "operation_description": "Isolate variable", "mapped_node_id": "SLE"}, {"step_index": 4, "type": "algebra", "instruction": "Hanapin ang x gamit ang x + y = 5.", "blank_expression": "x + 3 = 5, kaya ang x = ___", "correct_value": "2", "operation_description": "Solve for x", "mapped_node_id": "SLE"}]', '2026-05-21T12:38:31.454569+00:00', 'Si Aling Nena ay bumili ng kabuuang 5 notebook at ballpen para sa kanyang anak sa halagang 13 pesos. Kung ang bawat notebook ay nagkakahalaga ng 2 pesos at ang bawat ballpen ay 3 pesos, ilang notebook at ballpen ang kanyang binili?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('06a11105-895c-4cb7-b229-2d9d75786d12', 'SLE', 'x + 3*y = 10, x + y = 4', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang variable para sa bilang ng softdrinks.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 1, "type": "variable_id", "instruction": "Ibigay ang variable para sa bilang ng tinapay.", "blank_expression": "y = ___", "correct_value": "y", "operation_description": "Identify the variable", "mapped_node_id": "SLE"}, {"step_index": 2, "type": "algebra", "instruction": "I-subtract ang pangalawang equation mula sa una upang maalis ang x.", "blank_expression": "(x + 3y) - (x + y) = 10 - 4 => 2y = ___", "correct_value": "6", "operation_description": "Subtract equations", "mapped_node_id": "SLE"}, {"step_index": 3, "type": "algebra", "instruction": "I-divide ang magkabilang panig sa 2 para makuha ang y.", "blank_expression": "y = 6 / 2 => y = ___", "correct_value": "3", "operation_description": "Division property of equality", "mapped_node_id": "SLE"}, {"step_index": 4, "type": "algebra", "instruction": "I-substitute ang y = 3 sa x + y = 4 para mahanap ang x.", "blank_expression": "x + 3 = 4 => x = ___", "correct_value": "1", "operation_description": "Substitution method", "mapped_node_id": "SLE"}]', '2026-05-21T12:38:41.161639+00:00', 'Si Aling Nena ay bumili ng kabuuang 10 pirasong paninda para sa kanyang tindahan na binubuo ng ilang softdrinks at tinapay. Kung ang kabuuang halaga ng softdrinks (x) at tatlong beses ng tinapay (3y) ay 10, at ang kabuuang bilang ng mga item ay x + y = 4, ilan ang bawat isa?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('c470c04c-9137-485b-86fc-de0a4570fa26', 'RER', 'sqrt(16)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable para sa haba ng gilid ng garden.", "blank_expression": "s = \\sqrt{___}", "correct_value": "16", "operation_description": "Identify the variable", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Isulat ang 16 bilang square ng isang numero.", "blank_expression": "s = \\sqrt{4^2}", "correct_value": "4", "operation_description": "Simplify the radical", "mapped_node_id": "RER"}]', '2026-05-21T12:38:49.314913+00:00', 'Si Aling Nena ay may square na garden sa kanyang backyard na may area na 16 square meters. Kailangan niyang malaman ang haba ng bawat gilid ng kanyang garden para mabakuran ito nang tama.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ef7ebc3d-7fa5-407f-b4e4-88470e7c54cd', 'RER', 'sqrt(x^2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the side length s by taking the square root of the area x^2.", "blank_expression": "s = \\sqrt{___}", "correct_value": "x^2", "operation_description": "Write the equation", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Apply the property of radicals to the expression.", "blank_expression": "s = ___", "correct_value": "|x|", "operation_description": "Simplify the radical", "mapped_node_id": "RER"}]', '2026-05-21T12:39:00.438361+00:00', 'Aling Nena wants to calculate the exact side length of a square-shaped area in her sari-sari store where she plans to put a new display rack. If the area of the floor space is defined by the expression x^2 square meters, what is the side length of the space?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('dfec7369-7c54-4ae7-a4fb-3ccee0f642aa', 'RER', 'x^(1/2) * x^(1/2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang base ng expression.", "blank_expression": "base = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang product rule para sa exponents: pagsamahin ang exponents sa iisang base.", "blank_expression": "x ^ (___)", "correct_value": "1/2 + 1/2", "operation_description": "Apply product rule", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang fraction sa exponent.", "blank_expression": "x ^ (___)", "correct_value": "1", "operation_description": "Add fractions", "mapped_node_id": "RER"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang final answer nang walang exponent na 1.", "blank_expression": "___", "correct_value": "x", "operation_description": "Simplify exponent", "mapped_node_id": "RER"}]', '2026-05-21T12:39:09.971438+00:00', 'Si Aling Nena ay may square na garden sa harap ng kanyang sari-sari store kung saan ang haba ng bawat side ay kinakatawan ng x^(1/2) meters. Upang makuha ang kabuuang area ng garden, kailangan niyang i-multiply ang haba ng side sa sarili nito na x^(1/2) * x^(1/2).') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('fccd9815-7a81-4c8f-a042-9c7ac44f846d', 'RER', '27^(1/3)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the base and the exponent in the given expression.", "blank_expression": "Base = ___, Exponent = ___", "correct_value": "27, 1/3", "operation_description": "Identify the variable", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Rewrite the base 27 as a power with a prime factor.", "blank_expression": "(___)^(1/3)", "correct_value": "3^3", "operation_description": "Prime factorization", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "Apply the power of a power rule by multiplying the exponents.", "blank_expression": "3^(3 * 1/3) = 3^___", "correct_value": "1", "operation_description": "Simplify exponent", "mapped_node_id": "RER"}, {"step_index": 3, "type": "algebra", "instruction": "Evaluate the final result.", "blank_expression": "3^1 = ___", "correct_value": "3", "operation_description": "Final evaluation", "mapped_node_id": "RER"}]', '2026-05-21T12:39:25.846747+00:00', 'Aling Nena bought 27 small packs of peanuts for her sari-sari store, which she intends to arrange in a perfect cubic display box. To find the side length of this cube, you need to calculate the cube root of the total packs, which is represented by the expression 27^(1/3).') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('80edacf5-f74a-46a9-87f8-062e383cf8f5', 'RER', 'sqrt(9*x^2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa dami ng kendi sa bawat pack.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Isulat ang 9x^2 bilang square ng isang term.", "blank_expression": "\\sqrt{(___)^2}", "correct_value": "3x", "operation_description": "Simplify the radicand", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square root ng expression.", "blank_expression": "\\sqrt{9x^2} = ___", "correct_value": "3x", "operation_description": "Extract the root", "mapped_node_id": "RER"}]', '2026-05-21T12:39:37.344757+00:00', 'Si Aling Nena ay nag-iimbentaryo ng kanyang paninda sa sari-sari store kung saan ang kabuuang halaga ng isang partikular na bundle ng kendi ay kinakatawan ng expression na \sqrt{9x^2}. Kung ang x ay tumutukoy sa dami ng piraso ng kendi sa bawat pack, tulungan si Aling Nena na pasimplehin ang expression para makuha ang presyo sa bawat unit.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('20579b41-995f-4449-8da1-913796eeb13d', 'RER', 'x^(3/2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang radical form ng expression na x^(3/2).", "blank_expression": "x^(3/2) = ___", "correct_value": "\\sqrt{x^3}", "operation_description": "Write the equation", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Isulat ang x^3 bilang x^2 * x para mailabas ang perfect square sa radical.", "blank_expression": "\\sqrt{x^3} = \\sqrt{___ * x}", "correct_value": "x^2", "operation_description": "Factor the radicand", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "Ilabas ang square root ng x^2.", "blank_expression": "\\sqrt{x^2 * x} = ___\\sqrt{x}", "correct_value": "x", "operation_description": "Simplify the radical", "mapped_node_id": "RER"}]', '2026-05-21T12:39:46.597316+00:00', 'Si Aling Nena ay nagbebenta ng mga telang hugis-parisukat para sa kanyang pananahi. Ang area ng isang tela ay kinakatawan ng x^(3/2) square inches kung saan ang x ay ang haba ng gilid nito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d9ca858b-1cb7-4fc0-8ce2-b1be51b8ea3b', 'RER', '4^(1/2)', '[{"step_index": 0, "type": "variable_id", "instruction": "I-convert ang exponential form na 4^(1/2) sa radical form.", "blank_expression": "4^(1/2) = ___", "correct_value": "\\sqrt{4}", "operation_description": "Write the equation", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Kunin ang square root ng 4.", "blank_expression": "\\sqrt{4} = ___", "correct_value": "2", "operation_description": "Simplify radical", "mapped_node_id": "RER"}]', '2026-05-21T12:39:54.631240+00:00', 'Si Aling Nena ay may 4 na piraso ng itlog na nakapila sa isang parisukat na lalagyan. Upang malaman kung ilang piraso ng itlog ang bumubuo sa bawat gilid ng parisukat, kailangan mong kunin ang 4^(1/2).') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('465932cd-439c-4fb6-a74e-b6393d8aed11', 'RER', '8^(2/3)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang base at ang rational exponent na kailangang i-simplify.", "blank_expression": "x = 8^{\\frac{2}{3}}", "correct_value": "8^{\\frac{2}{3}}", "operation_description": "Identify the variable", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Isulat ang base na 8 bilang cube ng isang numero.", "blank_expression": "x = (___)^{\\frac{2}{3}}", "correct_value": "2^3", "operation_description": "Rewrite base", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "I-multiply ang mga exponent gamit ang power of a power rule.", "blank_expression": "x = 2^{3 \\cdot \\frac{2}{3}} = 2^{___}", "correct_value": "2", "operation_description": "Multiply exponents", "mapped_node_id": "RER"}, {"step_index": 3, "type": "algebra", "instruction": "I-compute ang huling halaga.", "blank_expression": "x = 2^2 = ___", "correct_value": "4", "operation_description": "Simplify", "mapped_node_id": "RER"}]', '2026-05-21T12:40:04.633115+00:00', 'Si Aling Nena ay may 8 kilo ng bigas na balak niyang ibenta sa mga suki. Kung ang presyo ng bawat kilo ay magiging katumbas ng 8 raised to the power of 2/3 pesos, magkano ang kabuuang presyo ng isang kilo ng bigas?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('62da7575-d41f-476a-8f17-26a145ee4d96', 'RER', 'sqrt(25*x^4)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mathematical expression para sa haba ng gilid ng garden sa pamamagitan ng pag-sqrt ng area.", "blank_expression": "s = \\sqrt{___}", "correct_value": "25x^4", "operation_description": "Write the equation", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Ihiwalay ang square root ng constant at ng variable term.", "blank_expression": "s = \\sqrt{25} \\cdot \\sqrt{___}", "correct_value": "x^4", "operation_description": "Product property of radicals", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square root ng 25 at i-simplify ang radical ng x^4.", "blank_expression": "s = 5 \\cdot ___", "correct_value": "x^2", "operation_description": "Simplify radicals", "mapped_node_id": "RER"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang huling sagot.", "blank_expression": "s = ___", "correct_value": "5x^2", "operation_description": "Final result", "mapped_node_id": "RER"}]', '2026-05-21T12:40:17.896439+00:00', 'Si Aling Nena ay may square na garden sa kanyang sari-sari store kung saan ang area ay katumbas ng 25x^4 square meters. Kailangan niyang malaman ang haba ng isang gilid ng kanyang garden upang lagyan ito ng bakod.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('155ff9e1-65d6-40f2-8e5d-d4600cc971db', 'RER', 'x^(2/3) * x^(1/3)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang kabuuang timbang ng asukal sa pamamagitan ng pag-multiply ng dalawang batch.", "blank_expression": "Total = ___ * x^(1/3)", "correct_value": "x^(2/3)", "operation_description": "Identify the variable", "mapped_node_id": "RER"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang product rule para sa exponents sa pamamagitan ng pag-add ng exponents.", "blank_expression": "x^(2/3 + 1/3) = x^(___)", "correct_value": "1", "operation_description": "Add fractions", "mapped_node_id": "RER"}, {"step_index": 2, "type": "algebra", "instruction": "Isulat ang huling sagot nang walang exponent na 1.", "blank_expression": "x^1 = ___", "correct_value": "x", "operation_description": "Simplify exponent", "mapped_node_id": "RER"}]', '2026-05-21T12:40:27.214046+00:00', 'Si Aling Nena ay nag-aayos ng kanyang sari-sari store at bumili ng dalawang batch ng asukal. Ang unang batch ay may timbang na x^(2/3) kg at ang ikalawang batch ay may timbang na x^(1/3) kg.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e9c9e80f-d21e-4f48-8fa4-23917401a03d', 'PO', '(x^2 + 2*x) + (x^2 - x)', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang ekspresyon para sa kabuuang halaga sa pamamagitan ng pag-add ng dalawang set.", "blank_expression": "___ = (x^2 + 2x) + (x^2 - x)", "correct_value": "Total Cost", "operation_description": "Write the equation", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga like terms o magkakaparehong variable.", "blank_expression": "(x^2 + x^2) + (2x - x) = ___", "correct_value": "2x^2 + x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "PO"}]', '2026-05-21T12:40:35.559199+00:00', 'Si Aling Nena ay bumili ng dalawang set ng school supplies para sa kanyang mga anak. Ang unang set ay nagkakahalaga ng (x^2 + 2x) pesos, at ang pangalawang set naman ay (x^2 - x) pesos. Magkano ang kabuuang halaga ng lahat ng kanyang binili?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('8cbc3979-822c-4f8c-84ca-209ff38bd0e0', 'AE', 'x^2 - x + 1', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang halaga ng x batay sa problem.", "blank_expression": "x = ___", "correct_value": "5", "operation_description": "Identify the variable", "mapped_node_id": "AE"}, {"step_index": 1, "type": "algebra", "instruction": "I-substitute ang x = 5 sa expression.", "blank_expression": "(___)^2 - 5 + 1", "correct_value": "5", "operation_description": "Substitution", "mapped_node_id": "AE"}, {"step_index": 2, "type": "algebra", "instruction": "I-evaluate ang exponent.", "blank_expression": "___ - 5 + 1", "correct_value": "25", "operation_description": "Exponentiation", "mapped_node_id": "AE"}, {"step_index": 3, "type": "algebra", "instruction": "Gawin ang pagbabawas at pagdaragdag para makuha ang final na sagot.", "blank_expression": "20 + 1 = ___", "correct_value": "21", "operation_description": "Arithmetic", "mapped_node_id": "AE"}]', '2026-05-21T12:59:01.646453+00:00', 'Si Aling Nena ay nagbebenta ng mga eco-bag sa kanyang sari-sari store. Ang kita niya sa isang araw ay kinakatawan ng expression na x^2 - x + 1, kung saan ang x ay ang bilang ng mga eco-bag na nabenta niya. Magkano ang kikitain ni Aling Nena kung nakabenta siya ng 5 eco-bag?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ae6097d7-0b58-46d1-bcb3-625c024e545e', 'PO', '(3*x^2 + x) - (x^2 + 2*x)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression para sa natitirang halaga ng paninda.", "blank_expression": "___ = (3x^2 + x) - (x^2 + 2x)", "correct_value": "V", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang negative sign sa loob ng panaklong.", "blank_expression": "3x^2 + x ___ - 2x", "correct_value": "-x^2", "operation_description": "Distribute negative", "mapped_node_id": "PO"}, {"step_index": 2, "type": "algebra", "instruction": "Pagsamahin ang mga like terms.", "blank_expression": "___ - x", "correct_value": "2x^2", "operation_description": "Combine like terms", "mapped_node_id": "PO"}]', '2026-05-21T12:59:17.814438+00:00', 'Si Aling Nena ay may sari-sari store. Ang kabuuang bilang ng kanyang paninda ay may halagang (3x^2 + x) pesos, ngunit kailangan niyang ibawas ang (x^2 + 2x) pesos para sa bayad sa delivery. Magkano ang matitirang halaga ng kanyang paninda?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('055643e2-60ed-4ee6-8f43-155defc86089', 'PO', '2*(x^2 + 3*x)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression para sa kabuuang gastos ng 2 set ng school supplies.", "blank_expression": "2 * (___ + 3x)", "correct_value": "x^2", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang 2 sa loob ng parenthesis.", "blank_expression": "___ + 6x", "correct_value": "2x^2", "operation_description": "Distribute", "mapped_node_id": "PO"}]', '2026-05-21T12:59:31.729574+00:00', 'Si Aling Nena ay bumili ng 2 set ng school supplies para sa kanyang mga anak. Ang bawat set ay may 1 notebook na nagkakahalagang x^2 piso at 3 ballpen na nagkakahalagang 3x piso.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('1bb01ba2-4343-4731-b4d9-380519d19cf5', 'PO', '(x^2)(x+1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression para sa kabuuang bilang ng kendi.", "blank_expression": "___ = x^2(x+1)", "correct_value": "Total", "operation_description": "Write the equation", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang x^2 sa loob ng parenthesis.", "blank_expression": "x^2(x) + x^2(1) = ___", "correct_value": "x^3 + x^2", "operation_description": "Distribute", "mapped_node_id": "PO"}]', '2026-05-21T12:59:45.437414+00:00', 'Si Aling Nena ay may sari-sari store at bumili siya ng x+1 na pakete ng kendi. Kung ang bawat pakete ay may laman na x^2 na piraso ng kendi, ilang piraso lahat ang kabuuang bilang ng kendi na binili niya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('6f632097-8344-447e-adb6-c037755ff6c3', 'PO', 'x*(x^2 - x + 1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa dami ng notebook.", "blank_expression": "dami = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang equation para sa kabuuang halaga.", "blank_expression": "kabuuang halaga = ___", "correct_value": "x(x^2 - x + 1)", "operation_description": "Write the equation", "mapped_node_id": "PO"}, {"step_index": 2, "type": "algebra", "instruction": "I-distribute ang x sa loob ng parenthesis.", "blank_expression": "___ + (-x^2) + x", "correct_value": "x^3", "operation_description": "Distribute", "mapped_node_id": "PO"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang huling simplified na polynomial.", "blank_expression": "x^3 - x^2 + ___", "correct_value": "x", "operation_description": "Simplify", "mapped_node_id": "PO"}]', '2026-05-21T12:59:59.494093+00:00', 'Si Aling Nena ay bumili ng x na dami ng notebook para sa kanyang tindahan. Ang bawat notebook ay nagkakahalaga ng x^2 - x + 1 na piso. Magkano ang kabuuang halaga ng mga notebook na binili ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('cc428961-4af3-4ea3-96d5-d39f7bcc6f89', 'PO', '(2*x^2 + x) + (x^2 - 3*x)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mga algebraic expression para sa halaga ng kendi at biscuit.", "blank_expression": "Halaga = (___) + (___)", "correct_value": "2x^2 + x, x^2 - 3x", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga like terms o magkakaparehong variable.", "blank_expression": "(2x^2 + x^2) + (x - 3x) = ___", "correct_value": "3x^2 - 2x", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "PO"}]', '2026-05-21T13:00:15.759950+00:00', 'Si Aling Nena ay bumili ng dalawang uri ng paninda para sa kanyang sari-sari store. Ang halaga ng mga kendi ay kinakatawan ng (2x^2 + x) na piso, habang ang halaga naman ng mga biscuit ay (x^2 - 3x) na piso. Magkano ang kabuuang halaga ng mga biniling paninda ni Aling Nena?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('68ff95c3-9344-4148-bd5e-557f52c3a1de', 'PO', '(x^3 + x^2) - x^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Ilista ang expression para sa bilang ng natitirang kendi.", "blank_expression": "___ = (x^3 + x^2) - x^2", "correct_value": "y", "operation_description": "Write the equation", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "Pagsamahin ang mga magkakatulad na term (like terms).", "blank_expression": "x^3 + ___", "correct_value": "0", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "PO"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang expression.", "blank_expression": "___", "correct_value": "x^3", "operation_description": "REMOVE_ADDING_ZERO", "mapped_node_id": "PO"}]', '2026-05-21T13:00:29.861050+00:00', 'Si Aling Nena ay may imbentaryo ng mga paninda sa kanyang sari-sari store. Noong umaga, mayroon siyang x^3 + x^2 na piraso ng kendi, ngunit nabenta niya ang x^2 na piraso sa mga estudyante. Ilan na lamang ang natitirang kendi sa kanyang tindahan?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('fb1ab2b4-1f7e-4b16-899e-0a14e519ebdd', 'PO', '3*x*(x + 2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable para sa bilang ng notebooks sa bawat pakete.", "blank_expression": "x = ___", "correct_value": "bilang ng notebooks", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang 3x sa loob ng parenthesis.", "blank_expression": "3x(x + 2) = ___", "correct_value": "3x^2 + 6x", "operation_description": "Distribute the term", "mapped_node_id": "PO"}]', '2026-05-21T13:00:43.424855+00:00', 'Si Aling Nena ay bumili ng 3 pakete ng notebooks para sa kanyang mga anak. Ang bawat pakete ay naglalaman ng x na piraso ng notebooks at 2 extra na pirasong ballpen sa loob nito.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('009be46d-6ce1-458c-aea9-3a284c48e288', 'PO', '(x^2 + 4*x) - (2*x^2 - x)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang ekspresyon para sa kabuuang kita.", "blank_expression": "Kabuuang kita = ___", "correct_value": "x^2 + 4x", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "variable_id", "instruction": "Tukuyin ang ekspresyon para sa puhunan.", "blank_expression": "Puhunan = ___", "correct_value": "2x^2 - x", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 2, "type": "algebra", "instruction": "I-distribute ang negative sign sa loob ng panaklong.", "blank_expression": "x^2 + 4x + ___ + x", "correct_value": "-2x^2", "operation_description": "DISTRIBUTE_NEGATIVE_ONE", "mapped_node_id": "PO"}, {"step_index": 3, "type": "algebra", "instruction": "Pagsamahin ang mga like terms.", "blank_expression": "___ + 5x", "correct_value": "-x^2", "operation_description": "COLLECT_AND_COMBINE_LIKE_TERMS", "mapped_node_id": "PO"}]', '2026-05-21T13:00:58.557210+00:00', 'Si Aling Nena ay may sari-sari store kung saan ang kabuuang kita niya sa pagbenta ng kape ay kinakatawan ng ekspresyong x^2 + 4x. Kung kailangan niyang ibawas ang halaga ng kanyang puhunan na 2x^2 - x, ano ang matitirang kita niya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('9c3c10ae-f0cc-42d2-b208-84056e419f64', 'PO', 'x^2*(x - 1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang mathematical expression para sa kabuuang halaga.", "blank_expression": "___ = x^2 * (x - 1)", "correct_value": "Total Cost", "operation_description": "Identify the variable", "mapped_node_id": "PO"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang x^2 sa loob ng parenthesis.", "blank_expression": "x^2 * (x - 1) = ___", "correct_value": "x^3 - x^2", "operation_description": "Distribute", "mapped_node_id": "PO"}]', '2026-05-21T13:01:11.990571+00:00', 'Si Aling Nena ay bumili ng x^2 na piraso ng ballpen para sa kanyang sari-sari store. Kung ang bawat piraso ay nagkakahalaga ng (x - 1) na piso, ano ang kabuuang halaga ng mga biniling ballpen?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('9ac6cdfb-2e64-42eb-8460-5fd2950778fc', 'PD', '(x^2 + 3*x + 2) / (x + 1)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang dividend at divisor mula sa word problem.", "blank_expression": "Dividend = ___, Divisor = x + 1", "correct_value": "x^2 + 3x + 2", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic expression sa numerator.", "blank_expression": "(x + 1)(x + 2) / (x + 1) = ___", "correct_value": "x + 2", "operation_description": "Factor the polynomial", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "I-cancel ang parehong term sa numerator at denominator.", "blank_expression": "x + 2 = ___", "correct_value": "x + 2", "operation_description": "Simplify the expression", "mapped_node_id": "PD"}]', '2026-05-21T13:01:25.928662+00:00', 'Si Aling Nena ay may kabuuang kita na x^2 + 3x + 2 na piso mula sa pagbenta ng kape sa loob ng (x + 1) na araw. Magkano ang kinikita niya bawat araw kung ang halaga ay pantay-pantay bawat araw?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('ddd12f79-e414-4c64-b8d2-4e639491ad9a', 'PD', '(x^2 - 4) / (x - 2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang algebraic expression para sa bilang ng kakanin na naibenta.", "blank_expression": "Bilang = ___", "correct_value": "(x^2 - 4) / (x - 2)", "operation_description": "Write the equation", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang numerator na x^2 - 4 gamit ang difference of two squares.", "blank_expression": "((x - 2)(x + 2)) / (x - 2) = ___", "correct_value": "x + 2", "operation_description": "Factor the polynomial", "mapped_node_id": "FP"}]', '2026-05-21T13:01:40.117979+00:00', 'Si Aling Nena ay may kabuuang kita na (x^2 - 4) pesos mula sa pagbenta ng ilang piraso ng kanyang special kakanin. Kung ang bawat piraso ay nagkakahalaga ng (x - 2) pesos, ilan ang kabuuang bilang ng kakanin na kanyang naibenta?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('1ce39f4d-ec86-4110-ba95-f5700f7d5666', 'PD', '(x^3 - x^2) / x', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the total profit expression from the problem.", "blank_expression": "Total Profit = ___", "correct_value": "x^3 - x^2", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "variable_id", "instruction": "Write the expression to find the profit per item by dividing the total profit by the number of items, x.", "blank_expression": "Profit per item = (x^3 - x^2) / ___", "correct_value": "x", "operation_description": "Write the equation", "mapped_node_id": "PD"}, {"step_index": 2, "type": "algebra", "instruction": "Break up the fraction into two separate terms.", "blank_expression": "___ + (-x^2 / x)", "correct_value": "x^3 / x", "operation_description": "Break up fraction", "mapped_node_id": "PD"}, {"step_index": 3, "type": "algebra", "instruction": "Subtract the exponents for the first term.", "blank_expression": "x^(3 - 1) - x", "correct_value": "x^(3 - 1)", "operation_description": "Subtract exponents", "mapped_node_id": "PD"}, {"step_index": 4, "type": "algebra", "instruction": "Simplify the final result.", "blank_expression": "x^2 - ___", "correct_value": "x", "operation_description": "Simplify", "mapped_node_id": "PD"}]', '2026-05-21T13:01:55.970698+00:00', 'A sari-sari store owner has a total profit of (x^3 - x^2) pesos from selling x items. If the profit per item is uniform, how much is the profit for each item?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('291ca525-6e86-459f-b9c1-17513bd6852b', 'PD', '(x^2 + 5*x + 6) / (x + 2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa dami ng customer at kabuuang halaga.", "blank_expression": "Dividend = ___, Divisor = ___", "correct_value": "x^2 + 5x + 6, x + 2", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic expression sa numerator.", "blank_expression": "(x + 3)(x + 2) / (x + 2) = ___", "correct_value": "x + 3", "operation_description": "Factor the numerator", "mapped_node_id": "PD"}]', '2026-05-21T13:02:19.360889+00:00', 'Si Aling Nena ay may kabuuang kita na (x^2 + 5x + 6) pesos mula sa kanyang sari-sari store ngayong araw. Kung mayroong (x + 2) na customer na bumili ng pare-parehong halaga ng paninda, magkano ang ginastos ng bawat isa?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('2c553a43-c56a-400e-aa6f-406271bf0e35', 'PD', '(x^2 - 9) / (x - 3)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang dividend at divisor mula sa word problem.", "blank_expression": "Dividend = ___, Divisor = x - 3", "correct_value": "x^2 - 9", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang numerator gamit ang difference of two squares.", "blank_expression": "(x + 3)(x - 3) / (x - 3) = ___", "correct_value": "x + 3", "operation_description": "Factor the numerator", "mapped_node_id": "FP"}]', '2026-05-21T13:02:34.534060+00:00', 'Si Aling Nena ay may kabuuang kita na (x^2 - 9) pesos mula sa pagbenta ng kanyang special pancit. Kung ang bawat plato ay nagkakahalaga ng (x - 3) pesos, ilang plato ng pancit ang naibenta niya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('4e224a6c-9c23-4242-a02e-d30c026a21d2', 'PD', '(x^3 + x^2) / x^2', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang ekspresyon para sa average na kita base sa ibinigay na sitwasyon.", "blank_expression": "Average = ___", "correct_value": "(x^3 + x^2) / x^2", "operation_description": "Write the equation", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "I-distribute ang denominator sa bawat term sa numerator.", "blank_expression": "___ + x^2 / x^2", "correct_value": "x^3 / x^2", "operation_description": "BREAK_UP_FRACTION", "mapped_node_id": "PD"}, {"step_index": 2, "type": "algebra", "instruction": "I-simplify ang division ng mga terms gamit ang exponent rule.", "blank_expression": "x^(3-2) + ___", "correct_value": "1", "operation_description": "CANCEL_TERMS", "mapped_node_id": "PD"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang final na pinasimple na sagot.", "blank_expression": "x + 1 = ___", "correct_value": "x + 1", "operation_description": "SIMPLIFY_ARITHMETIC", "mapped_node_id": "PD"}]', '2026-05-21T13:02:48.953843+00:00', 'Ang isang sari-sari store owner ay may kabuuang kita na (x^3 + x^2) pesos mula sa pagbenta ng kaniyang paninda sa loob ng x^2 na araw. Upang malaman ang average na kita niya bawat araw, kailangan niyang hatiin ang kabuuang kita sa dami ng araw.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('87969cfc-117d-45b8-9ae3-bf5203fb2535', 'PD', '(x^2 - x - 6) / (x + 2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang dividend at divisor mula sa problemang ibinigay.", "blank_expression": "Dividend: ___, Divisor: x + 2", "correct_value": "x^2 - x - 6", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic expression sa numerator.", "blank_expression": "(x + 2)(___) / (x + 2)", "correct_value": "x - 3", "operation_description": "Factor the numerator", "mapped_node_id": "PD"}, {"step_index": 2, "type": "algebra", "instruction": "I-cancel ang common factor na (x + 2) sa numerator at denominator.", "blank_expression": "___", "correct_value": "x - 3", "operation_description": "Simplify the fraction", "mapped_node_id": "PD"}]', '2026-05-21T13:03:02.739683+00:00', 'Si Aling Nena ay may kabuuang kita na (x^2 - x - 6) pesos mula sa pagbebenta ng kanyang mga kakanin sa loob ng (x + 2) na araw. Magkano ang kanyang average na kita bawat araw kung ang x ay kumakatawan sa isang variable ng bilang ng kanyang mga suki?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('8d90635c-bff8-49fb-a67d-01ee0cf3e112', 'PD', '(x^2 + 4*x + 4) / (x + 2)', '[{"step_index": 0, "type": "variable_id", "instruction": "I-identify ang expression para sa kabuuang kita.", "blank_expression": "Kabuuang kita = ___", "correct_value": "x^2 + 4x + 4", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "variable_id", "instruction": "I-identify ang presyo ng bawat pack.", "blank_expression": "Presyo bawat pack = ___", "correct_value": "x + 2", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 2, "type": "algebra", "instruction": "I-factor ang numerator.", "blank_expression": "(x^2 + 4x + 4) / (x + 2) = (___) / (x + 2)", "correct_value": "(x + 2)(x + 2)", "operation_description": "Factor the numerator", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "I-cancel ang common factor sa numerator at denominator.", "blank_expression": "(x + 2)(x + 2) / (x + 2) = ___", "correct_value": "x + 2", "operation_description": "Simplify the expression", "mapped_node_id": "PD"}]', '2026-05-21T13:03:16.698595+00:00', 'Si Aling Nena ay may kabuuang kita na (x^2 + 4x + 4) pesos mula sa pagtitinda ng kanyang mga paninda sa sari-sari store. Kung ang bawat pack ng meryenda ay nagkakahalaga ng (x + 2) pesos, ilang pack ng meryenda ang kanyang naibenta?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('af62cff5-b3b9-40e0-8a66-de7f6a8cc436', 'PD', '(x^3 - 8) / (x - 2)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the total volume of juice as the dividend and the number of containers as the divisor.", "blank_expression": "Dividend: ___, Divisor: x - 2", "correct_value": "x^3 - 8", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "Factor the difference of two cubes in the numerator.", "blank_expression": "(___)(x^2 + 2x + 4) / (x - 2)", "correct_value": "x - 2", "operation_description": "Factor the numerator", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Cancel the common factor (x - 2) from the numerator and the denominator.", "blank_expression": "Result = ___", "correct_value": "x^2 + 2x + 4", "operation_description": "Simplify the expression", "mapped_node_id": "PD"}]', '2026-05-21T13:03:30.340042+00:00', 'A sari-sari store owner has a total volume of juice represented by x^3 - 8 cubic centimeters to be packed equally into x - 2 smaller containers. How much volume will each container hold?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('2aa8541d-2ba8-44e4-8d27-3d394aa4668c', 'PD', '(x^2 - 16) / (x + 4)', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the dividend and the divisor from the problem.", "blank_expression": "Dividend: ___, Divisor: (x + 4)", "correct_value": "x^2 - 16", "operation_description": "Identify the variable", "mapped_node_id": "PD"}, {"step_index": 1, "type": "algebra", "instruction": "Factor the difference of two squares in the numerator.", "blank_expression": "(x^2 - 16) / (x + 4) = (___)(x - 4) / (x + 4)", "correct_value": "x + 4", "operation_description": "Factor the numerator", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Cancel the common factor from the numerator and the denominator.", "blank_expression": "((x + 4)(x - 4)) / (x + 4) = ___", "correct_value": "x - 4", "operation_description": "Simplify the expression", "mapped_node_id": "PD"}]', '2026-05-21T13:03:43.927163+00:00', 'A sari-sari store owner has a total profit of (x^2 - 16) pesos from selling snacks. If the number of items sold is represented by the expression (x + 4), how much is the price per item?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('46faa496-2b0b-47ca-9ab7-40146fbd8792', 'QE', 'x^2 + 6*x + 9 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa sukat ng gilid ng lalagyan.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "QE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic expression sa kaliwang bahagi.", "blank_expression": "(x + 3)^2 = ___", "correct_value": "0", "operation_description": "Factor the left side", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square root ng magkabilang panig upang mahanap ang x.", "blank_expression": "x + 3 = ___", "correct_value": "0", "operation_description": "Extract the root", "mapped_node_id": "QE"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve ang value ng x.", "blank_expression": "x = ___", "correct_value": "-3", "operation_description": "Solve for x", "mapped_node_id": "QE"}]', '2026-05-21T13:03:58.149160+00:00', 'Si Aling Nena ay nag-aayos ng display ng kanyang mga paninda sa sari-sari store. Ang area ng hugis-parisukat na lalagyan ng kanyang mga sardinas ay kinakatawan ng expression na x^2 + 6x + 9, na dapat ay katumbas ng zero para sa balanse ng shelf.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('4e4219ee-9527-4031-9a3d-7aced0df8416', 'QE', 'x^2 - 5*x + 6 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa dami ng balot ng kendi.", "blank_expression": "___ = x", "correct_value": "dami ng balot ng kendi", "operation_description": "Identify the variable", "mapped_node_id": "QE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic equation.", "blank_expression": "(x - 2)(x - ___) = 0", "correct_value": "3", "operation_description": "Factor the quadratic expression", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "I-set ang bawat factor sa zero.", "blank_expression": "x - 2 = 0 o x - 3 = ___", "correct_value": "0", "operation_description": "Zero Product Property", "mapped_node_id": "PD"}, {"step_index": 3, "type": "algebra", "instruction": "Lutasin ang x.", "blank_expression": "x = 2 o x = ___", "correct_value": "3", "operation_description": "Solve for x", "mapped_node_id": "QE"}]', '2026-05-21T13:04:12.378460+00:00', 'Si Aling Nena ay nag-aayos ng mga paninda sa kanyang sari-sari store. Ang bilang ng piraso ng kendi sa isang lalagyan ay sumusunod sa equation na x^2 - 5x + 6 = 0, kung saan ang x ay kumakatawan sa dami ng balot ng kendi.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('bafc032f-0b0e-4a21-97fc-afb3f7e109a2', 'QE', 'x^2 - 1 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "I-define ang x bilang side length ng garden plot.", "blank_expression": "x = ___", "correct_value": "side length", "operation_description": "Identify the variable", "mapped_node_id": "QE"}, {"step_index": 1, "type": "variable_id", "instruction": "Isulat ang equation batay sa word problem.", "blank_expression": "___ = 0", "correct_value": "x^2 - 1", "operation_description": "Write the equation", "mapped_node_id": "QE"}, {"step_index": 2, "type": "algebra", "instruction": "I-add ang 1 sa magkabilang side ng equation.", "blank_expression": "x^2 = ___", "correct_value": "1", "operation_description": "Addition Property of Equality", "mapped_node_id": "PE"}, {"step_index": 3, "type": "algebra", "instruction": "Kunin ang square root ng magkabilang side.", "blank_expression": "x = ___", "correct_value": "\\pm 1", "operation_description": "Extract the square root", "mapped_node_id": "QE"}]', '2026-05-21T13:04:27.963077+00:00', 'Si Aling Nena ay may garden plot na hugis square kung saan ang area nito ay 1 square meter. Kung ang area ay nakuha sa pamamagitan ng pag-subtract ng 1 sa square ng side length (x) ng plot, gaano kahaba ang side ng kanyang garden plot?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('6acc0303-2bea-465e-b629-1e34855750e6', 'QE', 'x^2 + 3*x - 10 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Ibigay ang equation base sa sitwasyon.", "blank_expression": "x^2 + 3x = ___", "correct_value": "10", "operation_description": "Write the equation", "mapped_node_id": "QE"}, {"step_index": 1, "type": "variable_id", "instruction": "I-rearrange ang equation para maging standard form na ax^2 + bx + c = 0.", "blank_expression": "x^2 + 3x - ___ = 0", "correct_value": "10", "operation_description": "Write the equation", "mapped_node_id": "QE"}, {"step_index": 2, "type": "algebra", "instruction": "I-factor ang quadratic expression.", "blank_expression": "(x + 5)(x - ___) = 0", "correct_value": "2", "operation_description": "Factor the expression", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve ang mga posibleng value ng x gamit ang zero product property.", "blank_expression": "x = -5 or x = ___", "correct_value": "2", "operation_description": "Solve for x", "mapped_node_id": "QE"}]', '2026-05-21T13:04:41.932617+00:00', 'Si Aling Nena ay nagbebenta ng mga notebook sa kanyang sari-sari store kung saan ang kabuuang kita (in pesos) ay kinakatawan ng ekspresyong x^2 + 3x. Kung ang target na kita niya ngayong araw ay 10 pesos, ano ang halaga ng x na dapat niyang makuha?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('420040af-76a4-4ee7-ac26-5da3480d8e7c', 'QE', 'x^2 - 7*x + 12 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa bilang ng mga produkto.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "QE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic expression.", "blank_expression": "(___)(x - 4) = 0", "correct_value": "x - 3", "operation_description": "Factor the quadratic equation", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang mga values ng x gamit ang zero product property.", "blank_expression": "x = 3, x = ___", "correct_value": "4", "operation_description": "Solve for x", "mapped_node_id": "QE"}]', '2026-05-21T13:04:56.732975+00:00', 'Si Aling Nena ay nag-aayos ng kanyang sari-sari store kung saan ang bilang ng kanyang mga softdrinks at sitsirya ay may kaugnayan sa isa''t isa. Kung ang bilang ng mga ito ay kinakatawan ng x at ang kabuuang bilang ay sumusunod sa equation na x^2 - 7x + 12 = 0, ilang softdrinks o sitsirya ang maaaring mayroon siya?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b8e4618f-348c-4389-a20f-823c7cbbdbe5', 'PE', 'x^3 - x = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable x na kumakatawan sa dami ng libong piraso ng eco-bag na ibinenta.", "blank_expression": "x^3 - x = ___", "correct_value": "0", "operation_description": "Write the equation", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang x mula sa kaliwang bahagi ng equation.", "blank_expression": "x(___^2 - 1) = 0", "correct_value": "x", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Gamitin ang difference of two squares para i-factor ang (x^2 - 1).", "blank_expression": "x(x - 1)(x + ___) = 0", "correct_value": "1", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "I-equate ang bawat factor sa zero upang mahanap ang mga value ng x.", "blank_expression": "x = 0, x = 1, x = ___", "correct_value": "-1", "operation_description": "Zero Product Property", "mapped_node_id": "PE"}]', '2026-05-21T13:05:24.728464+00:00', 'Ang isang maliit na negosyo ay nagbebenta ng mga eco-bag kung saan ang kita nito ay nakadepende sa dami ng units na x na ibinenta. Ang formula para sa kita ay ibinigay ng x^3 - x = 0, kung saan ang x ay ang dami ng libong piraso ng eco-bag na ibinenta.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('b931774e-2c32-40fb-9e87-0ce465b34878', 'PE', 'x^3 - 4*x = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kinakatawan ng sukat ng gilid ng kahon.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor out ang common variable na x sa kaliwang bahagi ng equation.", "blank_expression": "x(___ - 4) = 0", "correct_value": "x^2", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Gamitin ang difference of two squares para i-factor ang x^2 - 4.", "blank_expression": "x(x - 2)(___) = 0", "correct_value": "x + 2", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "I-set ang bawat factor sa zero para makuha ang mga roots.", "blank_expression": "x = 0, x = 2, x = ___", "correct_value": "-2", "operation_description": "Solving for roots", "mapped_node_id": "PE"}]', '2026-05-21T13:05:39.423360+00:00', 'Isang mag-aaral ang nagdidisenyo ng isang kahon para sa kanyang project kung saan ang volume ay kinakatawan ng ekspresyong x^3 - 4x. Kung nais niyang maging zero ang volume ng kahon para sa mga specific na sukat ng x, ano-ano ang posibleng values ng x?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('748234dd-1c3c-4db4-a6a1-99b44706c48e', 'PE', 'x^2*(x-1) = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa bilang ng mga bundle ng kendi.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Zero Product Property sa equation na x^2(x - 1) = 0.", "blank_expression": "x^2 = 0 \\text{ o } ___ = 0", "correct_value": "x - 1", "operation_description": "Zero Product Property", "mapped_node_id": "PE"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square root ng x^2 = 0.", "blank_expression": "x = ___", "correct_value": "0", "operation_description": "Solve for x", "mapped_node_id": "PE"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve ang x - 1 = 0.", "blank_expression": "x = ___", "correct_value": "1", "operation_description": "Solve for x", "mapped_node_id": "PE"}]', '2026-05-21T13:06:07.475997+00:00', 'Si Aling Nena ay nag-aayos ng kanyang benta sa sari-sari store. Ang kabuuang kita niya ay kinakatawan ng equation na x^2(x - 1) = 0, kung saan ang x ay kumakatawan sa bilang ng mga bundle ng kendi na kailangan niyang ibenta. Ilan ang mga posibleng halaga ng x para maging zero ang kita o maging balanse ang kanyang transaksyon?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('d7fcaa40-4936-498e-be0d-04fbb311ac9d', 'PE', 'x^3 - x^2 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the variable representing the number of units or profit factor.", "blank_expression": "___ = x", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "Factor out the greatest common monomial factor x^2 from the expression.", "blank_expression": "___(x - 1) = 0", "correct_value": "x^2", "operation_description": "Factoring", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "Set each factor to zero to solve for x.", "blank_expression": "x^2 = 0, x - 1 = ___", "correct_value": "0", "operation_description": "Zero Product Property", "mapped_node_id": "PO"}, {"step_index": 3, "type": "algebra", "instruction": "State the final values of x.", "blank_expression": "x = 0, x = ___", "correct_value": "1", "operation_description": "Solve for x", "mapped_node_id": "PE"}]', '2026-05-21T13:06:28.486489+00:00', 'A sari-sari store owner is calculating the profit function of a new item where the total profit is modeled by the equation x^3 - x^2 = 0. Find all possible values of x that result in zero profit for the business owner.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('9fe0306f-bf24-4053-bc41-2df8ca36a095', 'PE', 'x^3 + x^2 - 2*x = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "I-identify ang variable na kumakatawan sa bilang ng eco-bag.", "blank_expression": "___ = x", "correct_value": "Bilang ng eco-bag", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor out ang common na x sa bawat term.", "blank_expression": "x(x^2 + x - 2) = 0", "correct_value": "x(x^2 + x - 2) = 0", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "I-factor ang quadratic expression sa loob ng parenthesis.", "blank_expression": "x(___)(x - 1) = 0", "correct_value": "x + 2", "operation_description": "Factoring quadratic", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "Gamitin ang Zero Product Property para mahanap ang mga value ng x.", "blank_expression": "x = ___, x = -2, x = 1", "correct_value": "0", "operation_description": "Solving for x", "mapped_node_id": "QE"}]', '2026-05-21T13:06:43.335091+00:00', 'Ang isang batang negosyante sa palengke ay nagbebenta ng mga eco-bag kung saan ang kabuuang kita (in pesos) ay kinakatawan ng equation na x^3 + x^2 - 2x = 0. Ilang piraso ng eco-bag (x) ang dapat niyang maibenta para maging zero ang kanyang profit o break-even point?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('dc935896-5fb8-4106-b333-36485db7128d', 'PE', 'x^3 - 9*x = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the variable representing the number of units sold in hundreds.", "blank_expression": "___ = x", "correct_value": "units", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "Factor out the common monomial x from the expression.", "blank_expression": "x(___ - 9) = 0", "correct_value": "x^2", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "Factor the difference of two squares inside the parentheses.", "blank_expression": "x(x - 3)(___ + 3) = 0", "correct_value": "x", "operation_description": "Factoring", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "Equate each factor to zero to solve for the roots.", "blank_expression": "x = 0, x - 3 = 0, x + 3 = 0; roots are x = 0, ___, -3", "correct_value": "3", "operation_description": "Solve for x", "mapped_node_id": "PE"}]', '2026-05-21T13:06:58.456373+00:00', 'A sari-sari store owner is modeling the profit of a new product using the function P(x) = x^3 - 9x, where x represents the number of units sold in hundreds. Find the break-even points where the profit is exactly zero so the owner can determine when the business neither gains nor loses money.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('06aa25c7-8bc5-4838-8450-8a5961d97542', 'PE', 'x^2*(x+2) = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable sa equation.", "blank_expression": "___ = x", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "Gamitin ang Zero Product Property para ihiwalay ang mga factor.", "blank_expression": "x^2 = 0, ___ = 0", "correct_value": "x+2", "operation_description": "Zero Product Property", "mapped_node_id": "QE"}, {"step_index": 2, "type": "algebra", "instruction": "Kunin ang square root ng unang factor.", "blank_expression": "x = ___", "correct_value": "0", "operation_description": "Solve for x", "mapped_node_id": "QE"}, {"step_index": 3, "type": "algebra", "instruction": "I-solve ang ikalawang factor para makuha ang huling value ng x.", "blank_expression": "x = ___", "correct_value": "-2", "operation_description": "Solve for x", "mapped_node_id": "QE"}]', '2026-05-21T13:07:12.837652+00:00', 'Si Aling Nena ay nag-iipon para sa kanyang sari-sari store kung saan ang kabuuang kita ay kinakatawan ng equation na x^2(x+2) = 0. Tukuyin ang mga posibleng halaga ng x na magreresulta sa zero profit upang masuri niya ang kanyang negosyo.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('e39fb98a-fbbb-4499-b27d-276b7e851e38', 'PE', 'x^3 - 4*x^2 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable x na kumakatawan sa bilang ng eco-bags.", "blank_expression": "x = ___", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang common term na x^2 mula sa equation.", "blank_expression": "___(x - 4) = 0", "correct_value": "x^2", "operation_description": "Factoring", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "I-equate ang bawat factor sa zero para makuha ang mga roots.", "blank_expression": "x^2 = 0 ; x - 4 = ___", "correct_value": "0", "operation_description": "Zero Product Property", "mapped_node_id": "FP"}, {"step_index": 3, "type": "algebra", "instruction": "Isulat ang mga final values ng x.", "blank_expression": "x = 0, x = ___", "correct_value": "4", "operation_description": "Solving for x", "mapped_node_id": "PE"}]', '2026-05-21T13:07:30.982789+00:00', 'Si Aling Nena ay nagbebenta ng mga eco-friendly na eco-bag kung saan ang kabuuang kita niya ay kinakatawan ng polynomial na x^3 - 4x^2. Kung ang kita ay zero dahil sa dami ng nagastos sa materyales, ilan ang dami ng bags (x) na kailangan niyang mabenta upang maging zero ang profit?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('21986127-27ff-4550-aa39-a7b5481c31fa', 'PE', 'x*(x^2 - 5*x + 6) = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Tukuyin ang variable na kumakatawan sa sukat ng board.", "blank_expression": "___ = x", "correct_value": "x", "operation_description": "Identify the variable", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "I-factor ang quadratic expression sa loob ng parenthesis.", "blank_expression": "x(x - 2)(___) = 0", "correct_value": "x - 3", "operation_description": "Factor the quadratic", "mapped_node_id": "FP"}, {"step_index": 2, "type": "algebra", "instruction": "I-set ang bawat factor sa zero gamit ang Zero Product Property.", "blank_expression": "x = 0, x - 2 = 0, ___ = 0", "correct_value": "x - 3", "operation_description": "Apply Zero Product Property", "mapped_node_id": "QE"}, {"step_index": 3, "type": "algebra", "instruction": "Lutasin ang bawat equation para makuha ang mga roots.", "blank_expression": "x = 0, x = 2, x = ___", "correct_value": "3", "operation_description": "Solve for x", "mapped_node_id": "QE"}]', '2026-05-21T13:07:45.425391+00:00', 'Isang mag-aaral ang nagdidisenyo ng hugis ng isang wooden board para sa kanilang school project na may area na nakadepende sa haba na x. Kung ang equation na x(x^2 - 5x + 6) = 0 ay kumakatawan sa sukat ng board, ano ang mga posibleng halaga ng x?') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('25627d99-ff07-4ffc-b719-38c549c8304d', 'PE', 'x^3 - x^2 - x + 1 = 0', '[{"step_index": 0, "type": "variable_id", "instruction": "Identify the polynomial expression given in the problem.", "blank_expression": "___ = 0", "correct_value": "x^3 - x^2 - x + 1", "operation_description": "Write the equation", "mapped_node_id": "PE"}, {"step_index": 1, "type": "algebra", "instruction": "Factor by grouping the first two and last two terms.", "blank_expression": "x^2(x - 1) - 1(x - 1) = ___", "correct_value": "0", "operation_description": "Factor by grouping", "mapped_node_id": "FD"}, {"step_index": 2, "type": "algebra", "instruction": "Factor out the common binomial term (x - 1).", "blank_expression": "(x^2 - 1)(x - 1) = ___", "correct_value": "0", "operation_description": "Factorization", "mapped_node_id": "FD"}, {"step_index": 3, "type": "algebra", "instruction": "Factor the difference of two squares (x^2 - 1).", "blank_expression": "(x - 1)(x + 1)(x - 1) = ___", "correct_value": "0", "operation_description": "Difference of two squares", "mapped_node_id": "FD"}, {"step_index": 4, "type": "algebra", "instruction": "Solve for the roots by setting each factor to zero.", "blank_expression": "x = 1, x = -1, x = ___", "correct_value": "1", "operation_description": "Solve for roots", "mapped_node_id": "PE"}]', '2026-05-21T13:07:59.587081+00:00', 'A sari-sari store owner models the profit of a new product line using the polynomial function P(x) = x^3 - x^2 - x + 1, where x represents the price factor. To find the break-even points, the owner needs to solve for the values of x where the profit is zero.') ON CONFLICT DO NOTHING;
INSERT INTO practice_problems (id, node_id, problem_expr, steps_json, created_at, word_problem_text) VALUES ('batch', '_system', 'practice round summary', '[]', '1970-01-01T00:00:00+00:00', NULL) ON CONFLICT DO NOTHING;

-- Table: content_records
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('9f18f4a4-442a-462f-abe1-be24ad3749c5', 'QE', 'This module is about quadratic equations. A quadratic equation has a variable that is squared. It can be written in the form ax² + bx + c = 0. Here, a, b, and c are numbers, and ''a'' cannot be zero. The module will help you understand what a quadratic equation is.', 'Consider the situation: A garden''s length is 7m longer than its width and the area is 18 square meters. Let ''w'' be the width of the garden.
1. The length is 7m longer than the width, so the length is w + 7.
2. The area of a rectangle is length times width.
3. So, the equation is w(w + 7) = 18.
4. Distribute ''w'': w² + 7w = 18.
5. Move all terms to one side to set the equation to zero: w² + 7w - 18 = 0.
This is a quadratic equation.', 'Let''s look at another situation. The length of a rectangular board is 3m longer than the width and the perimeter is 25m. Let ''w'' be the width of the board.
1. The length is 3m longer than the width, so the length is w + 3.
2. The perimeter of a rectangle is 2 times the length plus 2 times the width.
3. So, the equation is 2(w + 3) + 2w = 25.
4. Distribute the 2: 2w + 6 + 2w = 25.
5. Combine like terms: 4w + 6 = 25.
6. Subtract 6 from both sides: 4w = 19.
7. Divide both sides by 4: w = 19/4.
This is not a quadratic equation because there is no squared term. We are asked to illustrate a quadratic equation. This example is to show how we set up equations from word problems.', 'grade9_quadratic_equations_intro.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('8c1e3ed5-6b29-44bd-b44e-bd1bad197391', 'SLE', 'We have learned about two forms of linear equations: the standard form (Ax + By = C) and the slope-intercept form (y = mx + b).  In the slope-intercept form, ''m'' tells us the steepness or slope of the line, and ''b'' tells us where the line crosses the y-axis (the y-intercept).

Sometimes, we need to change an equation from one form to another. This is like translating a sentence from one language to another. We will learn how to rewrite equations from standard form to slope-intercept form, and vice versa. This helps us understand the properties of the line, like its slope and y-intercept, more easily.', 'Let''s rewrite the equation 7x + 4y = 20 in slope-intercept form (y = mx + b).

1. The goal is to get ''y'' by itself on one side of the equation.
   7x + 4y = 20

2. Subtract 7x from both sides of the equation to move the ''x'' term to the other side.
   7x + 4y - 7x = 20 - 7x
   4y = 20 - 7x

3. Rearrange the terms on the right side to match the ''mx + b'' format. It''s better to put the ''x'' term first.
   4y = -7x + 20

4. Divide both sides of the equation by 4 to isolate ''y''.
   4y / 4 = (-7x + 20) / 4
   y = -7x/4 + 20/4

5. Simplify the fraction.
   y = -7/4x + 5

So, the equation 7x + 4y = 20 in slope-intercept form is y = -7/4x + 5. Here, the slope (m) is -7/4 and the y-intercept (b) is 5.', 'Let''s rewrite the equation y - 5 = 2/3(x - 3) in standard form (Ax + By = C).

1. Distribute the 2/3 on the right side of the equation.
   y - 5 = (2/3) * x - (2/3) * 3
   This is done to remove the parentheses and simplify the expression.

2. Simplify the multiplication.
   y - 5 = 2/3x - 2
   Multiplying 2/3 by 3 cancels out the denominator.

3. To eliminate the fraction, multiply every term in the equation by the denominator, which is 3.
   3 * (y - 5) = 3 * (2/3x - 2)
   This step clears the fraction to make the equation easier to work with.

4. Distribute the 3 on both sides.
   3y - 15 = 3 * (2/3x) - 3 * 2
   3y - 15 = 2x - 6
   This applies the distributive property to both sides of the equation.

5. Now, we want to arrange the equation in the form Ax + By = C. Move the ''x'' term to the left side by subtracting 2x from both sides.
   3y - 15 - 2x = 2x - 6 - 2x
   -2x + 3y - 15 = -6
   This step begins to group the x and y terms together on one side.

6. Move the constant term (-15) to the right side by adding 15 to both sides.
   -2x + 3y - 15 + 15 = -6 + 15
   -2x + 3y = 9
   This step isolates the terms with variables on the left and the constant on the right.

7. The standard form usually has a positive coefficient for A. Multiply the entire equation by -1.
   -1 * (-2x + 3y) = -1 * 9
   2x - 3y = -9
   This ensures the leading coefficient (A) is positive, which is a common convention for standard form.', 'grade8_systems_equations_algebraic.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('cc5cca73-867d-41dd-86b1-5ef21e8178ff', 'SP', 'Algebraic expressions are like number sentences but with letters. These letters, called variables, can stand for any number. We also have constants, which are just regular numbers.  When we put them together with operations like addition and subtraction, we get algebraic expressions. For example, ''5a - 75'' is an algebraic expression. 

Equations are statements that say two things are equal. They use an equals sign (=). Sometimes an equation has a variable. If it does, the equation might be true or false depending on what number we put in for the variable. The number that makes the equation true is called the solution. For example, ''5m + 20 = 10'' is an equation.

Linear equations in one variable are special equations. The highest power of the variable is always 1. Think of it like this: the variable is not squared (like x²) or cubed (like x³). These equations have a standard form: ax + b = c. The symbol ''='' shows that both sides are equal.', 'Solve the linear equation: 2x - 6 = 4

Step 1: Write down the equation.
2x - 6 = 4

Step 2: Add 6 to both sides of the equation to isolate the term with the variable.
2x - 6 + 6 = 4 + 6

Step 3: Simplify both sides.
2x = 10

Step 4: Divide both sides by 2 to solve for x.
2x / 2 = 10 / 2

Step 5: Simplify to find the value of x.
x = 5', 'Solve the linear equation: x - 4 > 2

Step 1: Write down the inequality.
x - 4 > 2

Step 2: Add 4 to both sides of the inequality. This is done to get the variable x by itself on one side.
x - 4 + 4 > 2 + 4

Step 3: Simplify both sides of the inequality.
x > 6

Step 4: This means any number greater than 6 will make the inequality true. For example, if we choose 7, we can check:
7 - 4 > 2
3 > 2
This is true, so numbers greater than 6 are the solutions.', 'grade7_special_products.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('a90dd6e5-3640-4f14-a71b-7b61e13e51e7', 'LE', 'Imagine you have a number multiplied by itself many times.  Exponents are a shorthand way to write this.  For example, instead of writing 2 x 2 x 2 x 2, we can write it as 2 with a small ''3'' next to it, like 2³. The small number, called the exponent, tells you how many times to multiply the base number by itself. So, 2³ means 2 multiplied by itself 3 times.', 'Let''s solve $3^4$.
1. Identify the base number. The base number is 3.
2. Identify the exponent. The exponent is 4.
3. Write out the multiplication. This means multiplying the base number (3) by itself 4 times.
   $3^4 = 3 	imes 3 	imes 3 	imes 3$
4. Perform the multiplication step by step.
   $3 	imes 3 = 9$
   $9 	imes 3 = 27$
   $27 	imes 3 = 81$
5. The answer is 81.
So, $3^4 = 81$.', 'Let''s solve $5^3$.
1. The base number is 5. This is the number we will multiply.
2. The exponent is 3. This tells us how many times to multiply the base number.
3. We will multiply the base number (5) by itself 3 times: $5 	imes 5 	imes 5$.
4. First, multiply the first two numbers: $5 	imes 5 = 25$. We do this to start the calculation.
5. Now, multiply the result by the remaining number: $25 	imes 5 = 125$. This completes the multiplication based on the exponent.', 'grade7_laws_of_exponents.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('de955a39-2675-4dee-be87-2c634912e6e6', 'OI', 'We can add integers using a number line. To add positive numbers, we move to the right on the number line. For example, to find 6 + 5, we start at 6 and move 5 steps to the right, landing on 11. When we add a negative number, we move to the left. For example, to find 7 + (-3), we start at 7 and move 3 steps to the left, landing on 4.

Another way to add integers is by using signed tiles. A positive tile represents +1, and a negative tile represents -1. When we combine a positive tile and a negative tile, they cancel each other out. If we combine tiles of the same sign, they add up. For example, combining four positive tiles and five positive tiles gives us nine positive tiles, which is 4 + 5 = 9. Combining three negative tiles and four negative tiles gives us seven negative tiles, which is (-3) + (-4) = -7.', 'Let''s find the sum of -5 and 3 using signed tiles.

Step 1: Represent -5 with five negative tiles. This looks like: -----
Step 2: Represent 3 with three positive tiles. This looks like: +++
Step 3: Combine all the tiles: -----
Step 4: Cancel out pairs of positive and negative tiles. We have three positive tiles and five negative tiles. We can cancel three pairs.

    -  -  -  -  -
    +  +  +

After canceling three pairs, we are left with two negative tiles: --
Step 5: The remaining tiles represent the sum. Two negative tiles represent -2.
Therefore, -5 + 3 = -2.', 'Let''s find the sum of -2 and -4 using signed tiles.

Step 1: Represent -2 with two negative tiles. This looks like: --
This step shows the first number in the addition problem.
Step 2: Represent -4 with four negative tiles. This looks like: ----
This step shows the second number in the addition problem.
Step 3: Combine all the tiles: -- ----
This step brings together all the tiles from both numbers.
Step 4: Since all the tiles are negative, we just count them. We have a total of six negative tiles.
This step shows that when adding two negative numbers, the result is also negative.
Step 5: The combined negative tiles represent the sum. Six negative tiles represent -6.
Therefore, -2 + (-4) = -6.', 'grade7_operations_integers.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('654a5171-ff26-4725-a413-19b089e76ae0', 'FD', 'This lesson is about multiplying simple fractions. To multiply fractions, you need to multiply the top numbers together. Then, multiply the bottom numbers together. The result you get is your answer. Sometimes, you can make your answer simpler. This is called simplifying or writing it in lowest term.', 'Multiply 1/5 by 3/4.
Step 1: Multiply the numerators (top numbers). 1 * 3 = 3.
Step 2: Multiply the denominators (bottom numbers). 5 * 4 = 20.
Step 3: Write the answer as a fraction. The answer is 3/20. This fraction is already in simplest form.', 'Multiply 3/8 by 2/3.
Step 1: Multiply the numerators. 3 * 2 = 6. This gives us the numerator of our new fraction.
Step 2: Multiply the denominators. 8 * 3 = 24. This gives us the denominator of our new fraction.
Step 3: Write the new fraction. We have 6/24. We can simplify this fraction.
Step 4: Find the greatest common factor of 6 and 24, which is 6. Divide both the numerator and denominator by 6. 6 / 6 = 1. 24 / 6 = 4. The simplified answer is 1/4.', 'grade6_fractions_multiplication.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', '{"lesson": "Multiplying fractions is easy. First, multiply the top numbers. Then, multiply the bottom numbers. Sometimes, you can make the fraction smaller. This is called simplifying.", "worked_example": "Multiply 1/2 by 1/3.\nStep 1: Multiply the top numbers: 1 * 1 = 1.\nStep 2: Multiply the bottom numbers: 2 * 3 = 6.\nStep 3: Put them together. The answer is 1/6.", "guided_explanation": "Multiply 2/4 by 1/2.\nStep 1: Multiply the top numbers: 2 * 1 = 2.\nStep 2: Multiply the bottom numbers: 4 * 2 = 8. This gives us 2/8.\nStep 3: We can simplify 2/8. Divide both numbers by 2.\nStep 4: 2 divided by 2 is 1. 8 divided by 2 is 4. The final answer is 1/4."}') ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('d1950351-8361-4bd0-a05f-9dedfa5657e2', 'L2V', 'A linear equation in two variables is an equation with two variables.  Each variable in the equation has an exponent of one. This means the degree of the equation is one. You will see variables in the numerator and not in the denominator. The standard form of a linear equation in two variables is Ax + By = C. Here, A, B, and C are numbers. A and B are the coefficients of x and y. C is the constant.', 'Let''s evaluate the linear equation 2x + 3y = 6 when x = 3 and y = 0.
Step 1: Write down the given linear equation: 2x + 3y = 6.
Step 2: Substitute the given value of x into the equation: 2(3) + 3y = 6.
Step 3: Substitute the given value of y into the equation: 2(3) + 3(0) = 6.
Step 4: Simplify the equation: 6 + 0 = 6.
Step 5: Check if the equation is true: 6 = 6. Yes, it is true.', 'Evaluate the linear equation x - 2y = 4 when x = 0 and y = -2.
Step 1: Write the equation: x - 2y = 4. This is the equation we need to check.
Step 2: Substitute the value of x: 0 - 2y = 4. We are putting the given value of x into the equation.
Step 3: Substitute the value of y: 0 - 2(-2) = 4. We are putting the given value of y into the equation.
Step 4: Simplify: 0 + 4 = 4. We are doing the multiplication.
Step 5: Final check: 4 = 4. This shows that the ordered pair (0, -2) makes the equation true.', 'grade8_slope_intercept.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('47f8d02e-2172-45fb-b952-2f153f539470', 'L1V', 'In math, we often have problems with unknown amounts.  We use letters, called variables, to stand for these unknowns.  An algebraic expression is a combination of numbers, variables, and math operations like addition, subtraction, multiplication, and division.  It''s like a math phrase that represents a quantity that might change or is not yet known.', 'Example: A store sells shirts for ''s'' pesos each. How much will 5 shirts cost?

1. Identify the cost of one shirt: The problem states that one shirt costs ''s'' pesos.
2. Identify the number of shirts: We want to find the cost of 5 shirts.
3. Multiply the cost per shirt by the number of shirts: To find the total cost, we multiply the price of one shirt by the number of shirts.
   Cost = (cost per shirt) x (number of shirts)
   Cost = s * 5
4. Write the algebraic expression: The expression representing the cost of 5 shirts is 5s pesos.', 'Example: Lito had ''p'' pesos. He spent 30 pesos on a book. How much money does he have left?

1. Identify Lito''s starting money: Lito started with ''p'' pesos.
   *This tells us the initial amount we are working with.*
2. Identify the amount Lito spent: He spent 30 pesos.
   *This is the amount being taken away from his money.*
3. Subtract the amount spent from the starting money: To find out how much money is left, we take away the money he spent from the money he had.
   Money left = (starting money) - (amount spent)
   Money left = p - 30
   *This step uses subtraction to represent the decrease in money.*
4. Write the expression for the money left: The expression representing the money Lito has left is p - 30 pesos.
   *This expression shows the final amount of money after the transaction.*', 'grade7_solving_equations.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('2faadd6e-2ae8-4a1a-8bc7-8e5233c02003', 'AE', 'In math, we use letters and numbers together to talk about things we don''t know yet or things that can change. This is called an algebraic expression. Think of it like a puzzle where letters stand for numbers.  An expression can be a single number, like 7, or a number with a letter, like 2x. It can also be more complex, like -3y + 4 or 4x - 3yz.

A ''term'' is a piece of an algebraic expression. It can be just a number (like 4), just a letter (like x), or a mix of numbers and letters multiplied together (like xy or 8yz). Polynomials are special kinds of algebraic expressions that are made by adding or subtracting these terms. The letters in a polynomial must have whole number powers, like x² or y³, not fractions or negative numbers.', 'Evaluate the expression 3x + 5 when x = 2.
1. Write down the expression: 3x + 5
2. Substitute the given value for the variable: 3(2) + 5
3. Perform the multiplication first: 6 + 5
4. Perform the addition: 11
So, when x = 2, the expression 3x + 5 is equal to 11.', 'Evaluate the expression 2y - 7 when y = 4.
1. Write the expression: 2y - 7.
2. Replace ''y'' with its given value: 2(4) - 7. This is done to find the numerical value of the expression.
3. Multiply 2 by 4: 8 - 7. Multiplication comes before subtraction according to the order of operations.
4. Subtract 7 from 8: 1. This gives us the final value of the expression.', 'grade7_algebraic_expressions.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('721d244b-4d95-4790-9e7d-46b1998d63ca', 'RPP', 'We often compare things in our daily lives. Sometimes we use fractions, and sometimes we use ratios. A ratio compares two or more amounts. For example, if there are 5 apples and 3 oranges, we can say the ratio of apples to oranges is 5 to 3. We can write this as 5:3.

Two ratios can be equal. When two ratios are equal, they form a proportion. For example, the ratio 2 to 3 is equal to the ratio 4 to 6. We can write this as 2:3 = 4:6. This means that if one amount doubles, the other amount also doubles to keep the ratio the same.

We can show proportions using models. If we have 2 mangoes for 3 glasses of shake, and we want to make more shake, we need to keep the ratio of mangoes to shake the same. If we want to make 6 glasses of shake (which is double 3 glasses), we will need 4 mangoes (which is double 2 mangoes). This shows 2:3 is the same as 4:6.', 'Mother uses 2 ripe mangoes to make 3 glasses of mango shake. She plans to make 9 glasses. How many mangoes does she need?

Step 1: Understand the problem.
We know the ratio of mangoes to glasses of shake is 2:3. We need to find out how many mangoes are needed for 9 glasses of shake.

Step 2: Identify the relationship.
The number of glasses of shake is changing from 3 to 9. We need to find out how this change affects the number of mangoes.

Step 3: Find the multiplier.
How many times did the number of glasses of shake increase? Divide the new number of glasses by the original number of glasses: 9 ÷ 3 = 3. The number of glasses tripled.

Step 4: Apply the multiplier to the mangoes.
Since the number of glasses of shake tripled, the number of mangoes needed will also triple. Multiply the original number of mangoes by 3: 2 x 3 = 6.

Step 5: State the answer.
Mother needs 6 ripe mangoes to make 9 glasses of mango shake. The proportion is 2:3 = 6:9.', 'One hot day, Mother uses 2 ripe mangoes to make 3 glasses of mango shake. She plans to make 9 glasses. How many mangoes does she need?

Step 1: Write the known ratio.
The problem tells us that 2 ripe mangoes are used for 3 glasses of mango shake. This can be written as the ratio 2:3 (mangoes to glasses).
This step helps us organize the information given in the problem.

Step 2: Write the unknown ratio.
We want to find out how many mangoes are needed for 9 glasses of mango shake. Let ''x'' be the unknown number of mangoes. This can be written as the ratio x:9.
This step sets up what we need to find.

Step 3: Set up a proportion.
Since the ratio of mangoes to glasses should remain the same, we can set the two ratios equal to each other: 2:3 = x:9.
This step uses the concept of proportion, which means the ratios are equivalent.

Step 4: Find the relationship between the known parts of the proportion.
Look at the second parts of the ratios (the number of glasses): 3 and 9. How do we get from 3 to 9? We multiply 3 by 3 (3 x 3 = 9).
This step helps us find how one ratio is related to the other.

Step 5: Apply the same relationship to the first parts of the proportion.
Since the number of glasses was multiplied by 3, we must also multiply the number of mangoes (the first part of the ratio) by 3. So, x = 2 x 3.
This step ensures that the proportion remains true, meaning the comparison of mangoes to glasses is consistent.

Step 6: Calculate the unknown value.
2 x 3 = 6. Therefore, x = 6.
This step gives us the final answer for the unknown quantity.

Step 7: State the answer.
Mother needs 6 ripe mangoes.', 'grade6_ratio_proportion.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('25331a2c-e413-4e43-b4bd-d2315affa783', 'RER', 'Sometimes, we see numbers with exponents that are fractions.  We can rewrite these expressions using radicals.  Think of the fraction''s bottom number as the root we need to find. The fraction''s top number tells us how to raise the base to a power.  We can also go the other way and write radical expressions using fractional exponents.', 'Let''s rewrite 27 to the power of 1/3 as a radical.
Step 1: Identify the base, numerator, and denominator. The base is 27, the numerator is 1, and the denominator is 3.
Step 2: The denominator of the fractional exponent becomes the index of the radical. So, we have a cube root (index of 3).
Step 3: The base stays the same under the radical symbol.
Step 4: The numerator of the fractional exponent becomes the exponent of the base under the radical. Since the numerator is 1, we can write it as 27^1.
Step 5: So, 27^(1/3) is equal to the cube root of 27 to the power of 1.
Step 6: This can be written as ³√27¹ or simply ³√27.
Therefore, 27^(1/3) = ³√27.', 'Let''s rewrite x^(3/4) as a radical.
Step 1: The base is x, the numerator is 3, and the denominator is 4. We do this to understand which part of the exponent goes where in the radical form.
Step 2: The denominator, 4, becomes the index of the radical. This tells us we are looking for the fourth root. So, we write ⁴√.
Step 3: The base, x, goes under the radical symbol. We now have ⁴√x.
Step 4: The numerator, 3, becomes the exponent of the base under the radical. This means x is raised to the power of 3. We write ⁴√x³.
Therefore, x^(3/4) is equal to the fourth root of x cubed.', 'grade9_radical_equations.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('eeb48fe9-54b6-45c0-95c3-776c3bd1f8ac', 'PE', 'Polynomials are algebraic expressions with variables that have whole number powers. We can describe polynomials by how many terms they have, like a monomial (one term) or a binomial (two terms). We also describe them by their degree, which is the highest exponent of the variable. A linear polynomial has a degree of 1, and a quadratic polynomial has a degree of 2.', 'Divide x^3 - 9x - 3x^2 + 27 by x + 3.
Step 1: Arrange the terms of the dividend (x^3 - 3x^2 - 9x + 27) and the divisor (x + 3) in descending order of their exponents. If a term is missing, use 0 as a placeholder.
Step 2: Divide the first term of the dividend (x^3) by the first term of the divisor (x). This gives x^2, which is the first term of the quotient.
Step 3: Multiply the divisor (x + 3) by the first term of the quotient (x^2). This gives x^3 + 3x^2.
Step 4: Subtract the result from Step 3 from the dividend. (x^3 - 3x^2 - 9x + 27) - (x^3 + 3x^2) = -6x^2 - 9x + 27.
Step 5: Bring down the next term of the dividend (-9x).
Step 6: Divide the first term of the new polynomial (-6x^2) by the first term of the divisor (x). This gives -6x, which is the second term of the quotient.
Step 7: Multiply the divisor (x + 3) by the second term of the quotient (-6x). This gives -6x^2 - 18x.
Step 8: Subtract the result from Step 7 from the polynomial in Step 4. (-6x^2 - 9x + 27) - (-6x^2 - 18x) = 9x + 27.
Step 9: Bring down the next term of the dividend (27).
Step 10: Divide the first term of the new polynomial (9x) by the first term of the divisor (x). This gives 9, which is the third term of the quotient.
Step 11: Multiply the divisor (x + 3) by the third term of the quotient (9). This gives 9x + 27.
Step 12: Subtract the result from Step 11 from the polynomial in Step 8. (9x + 27) - (9x + 27) = 0. The remainder is 0.
The quotient is x^2 - 6x + 9.', 'Divide x^2 + 5x + 6 by x + 2.
Step 1: Write the problem in long division form: (x^2 + 5x + 6) / (x + 2). We arrange the terms in descending order of exponents.
Step 2: Divide the first term of the dividend (x^2) by the first term of the divisor (x). This gives us ''x'', the first term of our quotient. We do this to find out what we need to multiply the divisor by to match the first term of the dividend.
Step 3: Multiply the divisor (x + 2) by ''x''. This gives x^2 + 2x. We do this to prepare for subtraction, aiming to eliminate the leading term of the dividend.
Step 4: Subtract (x^2 + 2x) from the dividend (x^2 + 5x + 6). This gives us 3x + 6. We subtract to remove the part of the dividend that matches our current quotient term.
Step 5: Bring down the next term of the dividend (+6). This gives us a new polynomial to work with: 3x + 6.
Step 6: Divide the first term of the new polynomial (3x) by the first term of the divisor (x). This gives us ''+3'', the next term of our quotient. We repeat the process to find the next multiplier for the divisor.
Step 7: Multiply the divisor (x + 2) by ''+3''. This gives us 3x + 6. We do this to match the current polynomial we are working with.
Step 8: Subtract (3x + 6) from the polynomial (3x + 6). This gives us 0. We subtract to see if there is anything left over after dividing.
The quotient is x + 3.', 'grade10_polynomial_roots.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', '{"lesson": "A polynomial is a math expression with variables like ''x''. We describe them by how many pieces they have. A ''monomial'' has one piece. A ''binomial'' has two pieces. We also look at the ''degree'', which is the highest exponent. A degree of 1 is called linear. A degree of 2 is called quadratic.", "worked_example": "Divide x^2 - 4x + 4 by x - 2.\nStep 1: Put terms in order from the highest exponent to the lowest.\nStep 2: Divide the first term of the top (x^2) by the first term of the side (x). You get x. This is the first part of your answer.\nStep 3: Multiply the side (x - 2) by your answer piece (x). You get x^2 - 2x.\nStep 4: Subtract (x^2 - 2x) from (x^2 - 4x). You get -2x.\nStep 5: Bring down the last number (+4). You now have -2x + 4.\nStep 6: Divide the first term of this (-2x) by the side (x). You get -2.\nStep 7: Multiply the side (x - 2) by -2. You get -2x + 4.\nStep 8: Subtract (-2x + 4) from (-2x + 4). You get 0. The final answer is x - 2.", "guided_explanation": "Divide x^2 + 3x + 2 by x + 1.\nStep 1: Write the problem like a long division problem.\nStep 2: Divide x^2 by x. The answer is x. Put this on top.\nStep 3: Multiply the side (x + 1) by your new top piece (x). You get x^2 + x.\nStep 4: Subtract (x^2 + x) from (x^2 + 3x). You get 2x.\nStep 5: Bring down the +2. Now you have 2x + 2.\nStep 6: Divide the new first term (2x) by the side (x). The answer is 2.\nStep 7: Multiply the side (x + 1) by 2. You get 2x + 2.\nStep 8: Subtract (2x + 2) from (2x + 2). You get 0. The answer is x + 2."}') ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('183c9a56-9a19-4662-bdce-66888c84d453', 'PD', 'An arithmetic sequence is a list of numbers where the difference between consecutive terms is constant. This constant difference is called the common difference, often shown as ''d''. For example, in the sequence 2, 4, 6, 8, the common difference is 2 because you add 2 to get the next number.  

The formula for finding the nth term of an arithmetic sequence is given by: an = a1 + d(n-1). Here, ''an'' is the term you want to find, ''a1'' is the first term in the sequence, ''d'' is the common difference, and ''n'' is the position of the term you are looking for. This formula helps us calculate any term in the sequence without having to list all the terms before it.', 'Find the 21st term of the arithmetic sequence: 6, 9, 12, 15,...

Step 1: Identify the first term (a1). 
From the sequence, the first term is 6. So, a1 = 6.

Step 2: Identify the common difference (d).
To find the common difference, subtract any term from its succeeding term. For example, 9 - 6 = 3. So, d = 3.

Step 3: Identify the term number (n) you want to find.
The problem asks for the 21st term, so n = 21.

Step 4: Use the formula for the nth term of an arithmetic sequence: an = a1 + d(n-1).
Substitute the values we found into the formula.
a21 = 6 + 3(21 - 1)

Step 5: Simplify the expression inside the parentheses.
a21 = 6 + 3(20)

Step 6: Perform the multiplication.
a21 = 6 + 60

Step 7: Perform the addition.
a21 = 66

Therefore, the 21st term of the arithmetic sequence is 66.', 'In the arithmetic sequence: 7, 10, 13, 16, . . .; find n if an = 304.

Step 1: Identify the first term (a1).
The first term in the sequence is 7. So, a1 = 7. This is the starting point of our sequence.

Step 2: Identify the common difference (d).
Subtract a term from the term that follows it. For example, 10 - 7 = 3. So, d = 3. This is the constant amount added to get the next term.

Step 3: Identify the nth term (an).
The problem states that the nth term is 304. So, an = 304. This is the value of the term we are trying to locate.

Step 4: Use the formula for the nth term of an arithmetic sequence: an = a1 + d(n-1).
We will use this formula to solve for ''n'', the position of the term.
304 = 7 + 3(n - 1)

Step 5: Distribute the common difference (d) to the terms inside the parentheses.
This step helps to simplify the equation by removing the parentheses. 3 * n = 3n and 3 * -1 = -3.
304 = 7 + 3n - 3

Step 6: Combine the constant terms on the right side of the equation.
This simplifies the equation by grouping similar terms together. 7 - 3 = 4.
304 = 4 + 3n

Step 7: Isolate the term with ''n'' by subtracting the constant term from both sides of the equation.
We do this to get the ''3n'' term by itself. 304 - 4 = 300.
300 = 3n

Step 8: Solve for ''n'' by dividing both sides of the equation by the coefficient of ''n''.
This will give us the value of ''n''. 300 / 3 = 100.
n = 100

Thus, 304 is the 100th term of the sequence.', 'grade10_rational_root_theorem.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('926b4e8c-43b4-4380-a711-07996d57fdf4', 'PO', 'Algebra is a part of math that uses letters and numbers. These letters and numbers can be combined with math symbols like plus and minus. This combination is called an algebraic expression.  

An algebraic expression can have parts called terms. A term can be a number, a letter, or numbers and letters multiplied together.  A polynomial is a special type of algebraic expression. It is made by adding terms. The letters in a polynomial must have whole number powers (like 2, 3, 4, not 1/2 or -2). Also, letters cannot be at the bottom of a fraction or under a square root sign.', 'Let''s find the degree and classification of the polynomial 5x^2 + 3x - 1.

Step 1: Identify the terms in the polynomial. The terms are 5x^2, 3x, and -1.
Step 2: Find the highest power of the variable in any term. The powers are 2 (in 5x^2), 1 (in 3x), and 0 (in -1, as x^0 = 1).
Step 3: The highest power is 2. So, the degree of the polynomial is 2.
Step 4: Count the number of terms. There are three terms.
Step 5: A polynomial with three terms is called a trinomial. Therefore, the classification is trinomial.', 'Let''s find the degree and classification of the polynomial 4y^3 - 2y + 7.

Step 1: Identify the terms: 4y^3, -2y, and 7.
This separates the expression into its individual parts.
Step 2: Find the highest power of the variable ''y''. The powers are 3, 1, and 0 (for the constant term 7).
This helps us determine the overall complexity of the polynomial.
Step 3: The highest power is 3.
This is the degree of the polynomial.
Step 4: Count the number of terms. There are three terms.
This tells us how to classify the polynomial.
Step 5: Since there are three terms, the polynomial is a trinomial.', 'grade7_algebraic_expressions.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
INSERT INTO content_records (id, node_id, lesson_text, worked_example, guided_explanation, source_doc, source_chunk_id, generated_at, simplified_lesson_text) VALUES ('c63f5425-be44-496c-90b6-3103e541aa7a', 'FP', 'Factoring polynomials means breaking down a polynomial into simpler expressions that, when multiplied together, produce the original polynomial. You can think of it as finding the ''ingredients'' that make up the expression. It is the reverse process of multiplying polynomials.

In this module, you will learn different techniques to factor polynomials. We start by looking for the Greatest Common Monomial Factor (GCMF). You will also learn special patterns like the difference of two squares and the sum and difference of two cubes to factor expressions completely and accurately.', 'Problem: Factor the expression 6x^2 + 12x.

1. Identify the greatest common factor (GCF) of the numerical coefficients 6 and 12, which is 6.
2. Identify the greatest common factor of the variables x^2 and x, which is x.
3. Combine these to find the GCMF, which is 6x.
4. Divide each term of the original polynomial by 6x: (6x^2 / 6x) = x and (12x / 6x) = 2.
5. Write the factored form as the GCMF multiplied by the resulting binomial: 6x(x + 2).', 'Problem: Factor the expression x^2 - 16.

1. Identify if the expression follows the pattern of the difference of two squares, where a^2 - b^2 = (a - b)(a + b). We do this to determine if the specific factoring rule for squares applies.
2. Recognize that x^2 is the square of x, and 16 is the square of 4. We do this to find the values of ''a'' and ''b'' for our pattern.
3. Apply the pattern using a = x and b = 4 to write the result as (x - 4)(x + 4). We do this to express the original polynomial as a product of its factors.', 'grade8_factoring_gcf.pdf', 'seed', '2026-05-21T21:22:11.218211+00:00', NULL) ON CONFLICT DO NOTHING;
